import type { Drill } from "./types";

// Service / senior drills, keyed by module slug — 25 per module.
// Multi-site or district manager, or service-business owner (restaurant group,
// cleaning company, security firm, salon chain, hotel): performance reviews
// across locations, budgets to head office or franchisor, underperforming-site
// conversations, vendor and lease negotiations, incidents, hiring managers,
// bank and investor conversations. Merged into course.ts.
export const SERVICE_SENIOR_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-svc-senior-01","level":"senior","profession":"service","title":"The weekly report that buries the miss","scenario":"You run six restaurants and send the ops director a weekly email. This week two sites missed their labor target by three points, but your draft opens with weather, foot traffic, and a long recap of a catering event.","task":"Write the opening 1-2 sentences so the miss is the first thing the director reads.","tips":["First sentence: which sites missed, by how much.","The catering recap is context — move it below.","If they read one line, it should be the thing that needs action."],"focus":["structure","clarity"],"placeholder":"Two of six sites missed labor target this week — Eastside by 3 points, Mill Road by 2."},
    {"id":"lead-svc-senior-02","level":"senior","profession":"service","title":"The deadline hidden in pleasantries","scenario":"You need a site manager's inventory counts by Friday to close the quarter. Your text starts with how busy her week must have been and a question about the new hire before the actual ask appears.","task":"Rewrite the message so the ask and the deadline come first.","tips":["Lead with what you need and by when.","One ask per message — the new-hire question can wait.","Warmth can follow the ask; it shouldn't hide it."],"focus":["clarity","concision"]},
    {"id":"lead-svc-senior-03","level":"senior","profession":"service","title":"The remodel deferral call","scenario":"The franchisor mandates a remodel at your Elm Street location this year, and you want a six-month deferral to protect cash through the slow season. You have thirty minutes with the field consultant and a habit of easing into big asks.","task":"Write the first two sentences of the call, stating the ask and the one-line reason.","tips":["Name the ask in sentence one: a six-month deferral for Elm Street.","Give the single strongest reason, not all five.","The consultant can't grant what you haven't clearly asked for."],"focus":["clarity","impact"],"placeholder":"I'm asking for a six-month deferral on the Elm Street remodel —"},
    {"id":"lead-svc-senior-04","level":"senior","profession":"service","title":"The guest injury escalation","scenario":"A guest slipped in the lobby of your hotel this morning and was taken to hospital; she is stable, the area is cordoned off, and you've pulled the camera footage. Your email to the owner starts with how the morning shift was staffed.","task":"Write a 2-3 sentence email that leads with what happened and the current status.","tips":["First line: the incident, the guest's condition, the scene status.","What you've already done comes second.","Save the staffing background for the incident report."],"focus":["clarity","structure"],"placeholder":"A guest was injured in a fall in the lobby this morning; she's in hospital and stable, and the area is secured."},
    {"id":"lead-svc-senior-05","level":"senior","profession":"service","title":"The line-of-credit ask","scenario":"You own a commercial cleaning company and need the bank to raise your line of credit from $50k to $100k before winter contracts start and payroll runs ahead of receivables. Your draft email walks through ten years of company history first.","task":"Write a 2-3 sentence email to your bank manager that leads with the ask.","tips":["Sentence one: the increase you want and when you need it.","One sentence on why: winter contracts pay in 60 days, payroll is weekly.","The history lives in the attached financials, not the email."],"focus":["clarity","impact"]},
    {"id":"lead-svc-senior-06","level":"senior","profession":"service","title":"The closure recommendation","scenario":"After four quarters of losses you've concluded the Northgate salon should close when its lease ends in March. Your memo to the owner currently opens with three pages of market analysis before the recommendation appears.","task":"Write the memo's opening 2 sentences: verdict first, then the one-line case.","tips":["State the recommendation in sentence one, including the timing.","Follow with the single decisive number.","Analysis supports a stated conclusion — it doesn't replace one."],"focus":["structure","impact"],"placeholder":"Recommendation: close Northgate when the lease ends in March."},
    {"id":"lead-svc-senior-07","level":"senior","profession":"service","title":"The rent abatement request","scenario":"Street reconstruction outside your busiest cafe has cut walk-in sales 40% for two months, with four months of work left. You're emailing the landlord to ask for a three-month rent reduction, but your draft spends two paragraphs on how good a tenant you've been.","task":"Write an email opening that puts the specific request in the first sentence.","tips":["Lead with the ask: a three-month reduction and the amount.","One line of evidence: the 40% sales drop, with dates.","Your tenant history is leverage — deploy it after the ask."],"focus":["clarity","precision"]},
    {"id":"lead-svc-senior-08","level":"senior","profession":"service","title":"Does the new site open on time?","scenario":"Head office asks one question: will the Lakeside location open March 3 as planned? It will, provided the fire inspection scheduled for the 24th passes. Your draft reply recaps the whole construction timeline before answering.","task":"Write a reply that answers first and carries the caveat second.","tips":["First word should carry the answer: yes.","One caveat, named precisely — the fire inspection date.","Nobody asked for the construction diary."],"focus":["concision","clarity"],"placeholder":"Yes — Lakeside opens March 3 as planned, with one dependency:"},
    {"id":"lead-svc-senior-09","level":"senior","profession":"service","title":"The policy change announcement","scenario":"Starting Monday, all eight of your locations must post schedules two weeks in advance instead of one. Your message to the managers' group chat opens with the survey results and turnover data that motivated the change, and the actual change appears in the sixth sentence.","task":"Rewrite the announcement so the change and its start date lead.","tips":["Sentence one: what changes and when it takes effect.","Rationale follows, in one or two lines.","Busy managers skim — the instruction must survive the skim."],"focus":["clarity","structure"]},
    {"id":"lead-svc-senior-10","level":"senior","profession":"service","title":"The inspection result relay","scenario":"The health inspection at your flagship restaurant just finished: passed, with two minor violations to correct within 14 days. The owner is anxious and waiting. Your draft text describes the inspector's walkthrough room by room.","task":"Write a 1-2 sentence message that leads with the verdict.","tips":["First word: passed.","Then the two violations and the 14-day clock.","An anxious reader needs the outcome before the tour."],"focus":["clarity","concision"],"placeholder":"We passed. Two minor violations — both fixable within the 14-day window:"},
    {"id":"lead-svc-senior-11","level":"senior","profession":"service","title":"The promotion pick","scenario":"HR asked who you're recommending for the open GM role at your Downtown location. You've decided on Dana, the assistant manager who ran the site solo through the summer. Your draft reply compares all three internal candidates at length before naming her.","task":"Write a reply that names your pick in the first sentence, reasons after.","tips":["Lead with the decision: Dana, for Downtown GM.","Give the two strongest reasons, not the full comparison.","The also-rans deserve a line, not a page."],"focus":["structure","clarity"]},
    {"id":"lead-svc-senior-12","level":"senior","profession":"service","title":"The vendor switch memo","scenario":"You've priced out switching linen suppliers across your four hotels and the move saves $2,100 a month with equal quality, verified over a 60-day trial at one property. Your memo to head office opens with the history of the current vendor relationship.","task":"Write the memo's first 2 sentences: recommendation and headline number first.","tips":["Sentence one: switch, to whom, saving how much.","Sentence two: the proof — the 60-day trial result.","History explains the past; the reader is buying the future."],"focus":["impact","precision"],"placeholder":"Recommendation: switch linen supply to Meridian across all four properties, saving $2,100/month."},
    {"id":"lead-svc-senior-13","level":"senior","profession":"service","title":"The overtime spike heads-up","scenario":"Overtime doubled at two of your sites this pay period — an extra $6,400 — because both lost a supervisor in the same month. The owner will see it in the payroll report Friday. Your draft message opens with the hiring pipeline update.","task":"Write a heads-up that leads with the number, then the cause and fix.","tips":["Lead with the figure the owner will see: $6,400 over.","Cause in one line; your fix and its date in another.","Getting ahead of the report is the point — don't bury the lede you're pre-empting."],"focus":["precision","impact"],"placeholder":"Heads-up before Friday's payroll report: overtime ran $6,400 over at Eastside and Mill Road."},
    {"id":"lead-svc-senior-14","level":"senior","profession":"service","title":"The investor good news","scenario":"Your two outside investors get a quarterly note. This quarter revenue came in 8% over plan and the new location broke even three months early. Your draft opens with a meditation on market conditions.","task":"Write an opening 1-2 sentences that lead with the results.","tips":["Good news is a headline — treat it like one.","Both numbers in the first two sentences.","Market commentary can support the numbers, not precede them."],"focus":["impact","concision"]},
    {"id":"lead-svc-senior-15","level":"senior","profession":"service","title":"The mid-shift walkout","scenario":"Three servers quit mid-shift Saturday night at your Riverside restaurant. The site stayed open — the GM pulled two staff from your nearest location and worked the floor herself. Your Sunday message to the ops director starts with the backstory of the conflict.","task":"Write a 2-3 sentence message that leads with status: open, covered, and how.","tips":["First line: the site is covered and operating.","Then what happened, in one factual sentence.","Root cause and your plan can be the follow-up, flagged clearly."],"focus":["clarity","structure"]},
    {"id":"lead-svc-senior-16","level":"senior","profession":"service","title":"The viral one-star review","scenario":"A one-star review with video of a billing dispute at your salon is being shared widely — 40,000 views overnight. You've reviewed the footage, refunded the client, and drafted a public reply. Your message to the owner opens with a defense of the stylist involved.","task":"Write a message that leads with the situation and the action already taken.","tips":["First line: what's spreading and how far.","Second: what you've already done — refund, draft reply.","The stylist's side belongs in the incident review, not the alert."],"focus":["clarity","impact"],"placeholder":"A one-star video review of a billing dispute at Kingsway hit 40k views overnight. Here's where we are:"},
    {"id":"lead-svc-senior-17","level":"senior","profession":"service","title":"The insurance claim update","scenario":"The insurer approved the water-damage claim for your hotel's third floor at $18,000, with payment in ten business days. The owner has asked about it twice this week. Your draft reply narrates every call with the adjuster.","task":"Write a 1-2 sentence update that leads with the outcome.","tips":["Approved, $18,000, ten business days — that's the message.","The adjuster saga is available on request.","Answer the question they've asked twice, first."],"focus":["concision","precision"]},
    {"id":"lead-svc-senior-18","level":"senior","profession":"service","title":"The budget cover email","scenario":"You're submitting the annual district budget to head office: $1.2M operating expense, up 4%, driven almost entirely by the wage floor increase. The approval decision is theirs. Your cover email currently opens with thanks for their support this year.","task":"Write a cover email opening that leads with the ask and the headline numbers.","tips":["Sentence one: what you're asking them to approve.","Sentence two: the one driver of the increase.","Gratitude closes an email well; it opens one badly."],"focus":["structure","precision"],"placeholder":"Requesting approval of the FY district budget: $1.2M opex, up 4% — the increase is almost entirely the new wage floor."},
    {"id":"lead-svc-senior-19","level":"senior","profession":"service","title":"The freezer decision","scenario":"The walk-in freezer at your flagship failed overnight. Repair is $4,000 with parts arriving tomorrow; replacement is $15,000 with a Friday install. You need the owner's call within the hour, but your draft opens with how the failure was discovered.","task":"Write a message that puts the decision and the deadline first, then the two options.","tips":["Lead with: decision needed within the hour, repair or replace.","Give each option one line: cost, timing, risk.","Discovery details don't change the decision — cut them."],"focus":["clarity","structure"],"placeholder":"Need your call within the hour: repair the walk-in for $4k (running tomorrow) or replace for $15k (Friday)."},
    {"id":"lead-svc-senior-20","level":"senior","profession":"service","title":"The audit score relay","scenario":"The franchisor's audit at your Elm Street site came back at 86 — below the 90 required — with the gaps in temperature logging and storage labeling. You're messaging that site's manager, and your draft eases in with everything the team did well.","task":"Write a message that leads with the score and the two gaps.","tips":["First line: 86 against a required 90, and the two failed areas.","Strengths can follow — they're real, but they're not the news.","End with the re-audit date so the clock is explicit."],"focus":["clarity","precision"]},
    {"id":"lead-svc-senior-21","level":"senior","profession":"service","title":"The Sunday hours decision","scenario":"Sunday service at your Mill Road location loses about $700 a week, but cutting it affects twelve staff shifts and one loyal breakfast crowd. You want the regional VP to make the call. Your draft email presents the dilemma as a long narrative.","task":"Write an email opening that states the decision needed and by when, then frames the two options in a line each.","tips":["Lead with: decision needed on Sunday hours at Mill Road by month end.","Option per line: keep (cost) vs. cut (impact).","A bounded choice gets decided; a narrative gets filed."],"focus":["structure","clarity"]},
    {"id":"lead-svc-senior-22","level":"senior","profession":"service","title":"The contract win announcement","scenario":"Your security firm just won the Harbourfront mall contract — $340k a year, your largest ever, starting May 1. Your note to the leadership group starts with the length of the RFP process.","task":"Write a 1-2 sentence announcement that leads with the win.","tips":["The win, the value, the start date — sentence one.","What it took to win can be the toast later.","Name the next operational step so momentum is immediate."],"focus":["impact","concision"],"placeholder":"We won Harbourfront — $340k/year, our largest contract, starting May 1."},
    {"id":"lead-svc-senior-23","level":"senior","profession":"service","title":"The opening date slips","scenario":"A permit delay pushes your new location's opening from April 3 to April 24. Head office planned marketing around the original date. Your draft message explains the municipal backlog in detail before mentioning the new date.","task":"Write a 2-3 sentence message that states the new date up front.","tips":["New date first — that's what every downstream plan needs.","Cause in one clause, not one paragraph.","Name what you've already moved (marketing, hiring starts) to show control."],"focus":["clarity","impact"],"placeholder":"Lakeside's opening moves to April 24 — a three-week slip caused by the permit backlog."},
    {"id":"lead-svc-senior-24","level":"senior","profession":"service","title":"Renew or relocate","scenario":"The lease on your best-performing salon expires in September; the landlord wants a 15% increase, and a comparable space two blocks away is available at current rates but needs a $60k fit-out. The owner must choose by June 1. Your draft email is a property-market essay.","task":"Write an email opening that leads with the decision and the deadline, then gives each option one line.","tips":["First sentence: the choice and the June 1 deadline.","One line per option: cost, disruption, risk.","Add your recommendation — you're closest to the numbers."],"focus":["structure","impact"]},
    {"id":"lead-svc-senior-25","level":"senior","profession":"service","title":"The quarterly review opener","scenario":"You're sitting down with a site manager whose quarter was genuinely mixed: sales up 6%, but two failed brand audits. Your instinct is ten minutes of small talk and then a slow build. She deserves the headline straight.","task":"Write the first two sentences of the review, stating the overall verdict and both headlines.","tips":["Open with your honest overall read — good quarter with one serious gap.","Name both facts in the first breath: the 6% and the audits.","The rest of the hour is for the conversation, not the reveal."],"focus":["clarity","structure"]}
  ],
  "start-with-the-audience": [
    {"id":"audience-svc-senior-01","level":"senior","profession":"service","title":"Covers and labor % for a banker","scenario":"Your bank manager asked how the restaurant group is doing before renewing your operating line. Your instinct is to talk covers, labor percentage, and food cost. She cares about one thing: whether cash flow comfortably services the debt.","task":"Write a 3-4 sentence summary in the banker's terms, not the operator's.","tips":["Translate operating metrics into cash flow and coverage.","Lead with the number she'll test: months of comfortable debt service.","Keep one operating detail only if it explains the cash story."],"focus":["audience","clarity"],"placeholder":"Cash flow covered our loan payments 2.3 times over the last twelve months —"},
    {"id":"audience-svc-senior-02","level":"senior","profession":"service","title":"The POS change for front-line staff","scenario":"You're rolling out a new point-of-sale system across all locations Monday. Your draft memo to staff explains the vendor selection, the integration timeline, and the reporting benefits. A server needs to know exactly one thing: what's different when they clock in Monday.","task":"Rewrite the staff notice in 3-4 sentences focused on what changes for them.","tips":["Their stake: login, ordering, tips, who to ask for help.","Cut the procurement story entirely.","Name the support person for week one."],"focus":["audience","concision"]},
    {"id":"audience-svc-senior-03","level":"senior","profession":"service","title":"The patio pitch to the landlord","scenario":"You want the landlord's consent for a summer patio at your cafe. Your draft is all about your revenue upside. His stake is different: property value, other tenants, liability, and appearance.","task":"Write a 3-4 sentence request framed around what the landlord cares about.","tips":["Lead with his upside: an anchored tenant and a livelier frontage.","Address liability and appearance before he asks.","Your revenue matters to him only as covenant strength — frame it that way."],"focus":["audience","impact"]},
    {"id":"audience-svc-senior-04","level":"senior","profession":"service","title":"The P&L pack for a first-time manager","scenario":"Your newest site manager came up through the kitchen and has never read a P&L. You're sending her first weekly pack. Your usual cover note assumes fluency in COGS, prime cost, and variance-to-plan.","task":"Write a 4-5 sentence cover note that makes the pack usable to a first-time reader.","tips":["Name the three lines that matter and what 'good' looks like on each.","Define one term you can't avoid; cut the rest.","Tell her what decision each number should drive, not just what it measures."],"focus":["audience","clarity"],"placeholder":"Three numbers matter in this pack, and here's what good looks like on each:"},
    {"id":"audience-svc-senior-05","level":"senior","profession":"service","title":"The labor variance for head-office finance","scenario":"Head-office finance flagged your district's labor variance and asked for an explanation. Your instinct is to tell shift-by-shift stories about call-outs and a flu wave. Finance wants drivers, dollars, and whether the run-rate is fixed.","task":"Write a 3-4 sentence explanation in finance's language: driver, dollar impact, run-rate outlook.","tips":["Quantify each driver — 'a flu wave' becomes 'unplanned backfill, $9,200'.","Say explicitly whether the variance recurs next month.","Stories persuade operators; bridges persuade finance."],"focus":["audience","precision"]},
    {"id":"audience-svc-senior-06","level":"senior","profession":"service","title":"The renovation closure notice for guests","scenario":"Your restaurant closes for two days next month to replace the kitchen line. Your draft customer notice explains equipment lifecycle and capital planning. Guests care about three things: which days, whether their booking survives, and what they get for the inconvenience.","task":"Write a 3-4 sentence guest notice answering only what guests care about.","tips":["Dates first, in plain calendar terms.","Say what happens to existing reservations without being asked.","One warm line about what they'll notice when you reopen."],"focus":["audience","concision"],"placeholder":"We're closing for two days — Tuesday March 10 and Wednesday March 11 — to rebuild our kitchen."},
    {"id":"audience-svc-senior-07","level":"senior","profession":"service","title":"The local promotion in brand terms","scenario":"You want franchisor approval for a local school-sports sponsorship at two sites. Your draft argues local revenue. The franchisor's lens is brand consistency, precedent for other franchisees, and trademark use.","task":"Write a 3-4 sentence request framed around the franchisor's concerns.","tips":["Address brand standards and logo use up front.","Name the precedent question yourself and bound it: two sites, one season.","Local revenue is your reason; compliance is their permission."],"focus":["audience","structure"]},
    {"id":"audience-svc-senior-08","level":"senior","profession":"service","title":"The kitchen fire for the adjuster","scenario":"A small fire closed your kitchen for one night. Writing to the insurance adjuster, your draft reads like an apology to a customer — reassuring tone, minimizing language. An adjuster needs facts: time, origin, response, damage, and mitigation.","task":"Rewrite the account in 4-5 factual sentences suited to a claims file.","tips":["Chronology with times; no emotional framing in either direction.","Never minimize ('minor', 'nothing serious') — describe and quantify.","State mitigation steps taken; that's what the adjuster is scoring."],"focus":["audience","precision"]},
    {"id":"audience-svc-senior-09","level":"senior","profession":"service","title":"The chemical procedure for the crew","scenario":"Your cleaning company is introducing a new disinfectant that must never be mixed with the degreaser. Many of your crew read English as a second language. Your draft memo uses phrases like 'incompatible chemical interactions' and 'adhere to dilution protocols'.","task":"Rewrite the safety instruction in 3-4 short, plain sentences anyone can follow.","tips":["Short sentences, common words, one instruction each.","Say what to do and what never to do — concretely.","If a sentence needs a dictionary, it fails as a safety instruction."],"focus":["audience","clarity"],"placeholder":"New rule, and it matters: never mix the blue disinfectant with the degreaser."},
    {"id":"audience-svc-senior-10","level":"senior","profession":"service","title":"The plain-English investor summary","scenario":"Your uncle put $150k into the salon chain and reads your quarterly update at his kitchen table. Your draft is full of same-store sales, EBITDA, and utilization rates. He wants to know: is the business healthy, and is my money safe?","task":"Write a 3-4 sentence quarterly summary a non-industry investor understands.","tips":["Answer his two real questions first: healthy? safe?","Translate each metric or drop it — 'chairs are busier' beats 'utilization up 6%… ' only if you add the number plainly.","One honest sentence on the thing you're watching."],"focus":["audience","clarity"]},
    {"id":"audience-svc-senior-11","level":"senior","profession":"service","title":"The corrective-action letter","scenario":"The health inspector requires a written response to two violations. Your draft explains how busy the season has been and how good your record was before. The inspector needs exactly one thing: each violation, the corrective action, and the completion date.","task":"Write a 3-4 sentence response structured around what the inspector will file.","tips":["One violation, one action, one date — twice.","Cut every sentence of context or reputation defense.","Verifiable actions ('installed a second thermometer, log attached') beat intentions."],"focus":["audience","precision"]},
    {"id":"audience-svc-senior-12","level":"senior","profession":"service","title":"The price increase, staff version","scenario":"Menu prices rise 5% next month. You're writing the version for your staff — the people who will face customers about it. Your draft is the finance rationale you sent head office: commodity inflation and margin protection.","task":"Write a 3-4 sentence staff note that equips them to answer a customer's 'why?'","tips":["Their stake: what to say when a regular asks.","Give them one honest, repeatable sentence for the floor.","Margin language belongs to head office; keep the staff version human."],"focus":["audience","clarity"],"placeholder":"Prices go up 5% on the 1st. When a guest asks why, here's the honest answer:"},
    {"id":"audience-svc-senior-13","level":"senior","profession":"service","title":"The GM job ad","scenario":"You're hiring a general manager for your busiest hotel. Your draft posting is a fourteen-bullet duty list copied from the HR file. The candidate you actually want — currently employed, not desperate — reads job ads asking one question: what's in this for my career?","task":"Rewrite the opening 3-4 sentences of the posting around the candidate's stake.","tips":["Lead with the scope and autonomy they'd gain, with real numbers.","Say what success looks like in year one.","Duty lists screen out the ambitious; a real challenge attracts them."],"focus":["audience","impact"]},
    {"id":"audience-svc-senior-14","level":"senior","profession":"service","title":"The uniform policy for part-timers","scenario":"You're announcing a stricter uniform policy to a workforce that's largely students on their first job. Your draft cites brand-standard clause numbers and 'professional presentation requirements'. Half of them won't finish reading it.","task":"Rewrite the announcement in 3-4 sentences pitched at a 17-year-old's first job.","tips":["Say exactly what to wear and from when — no clause numbers.","Explain why in one sentence a teenager finds fair.","State the consequence plainly but without menace."],"focus":["audience","clarity"]},
    {"id":"audience-svc-senior-15","level":"senior","profession":"service","title":"The patrol notice for residents","scenario":"Your security firm won the contract for a residential complex, and you're introducing the service to residents. Your draft lists patrol frequencies, response SLAs, and equipment specs. Residents want to feel safer, know what they'll see change, and know who to call.","task":"Write a 3-4 sentence resident notice in their terms.","tips":["Lead with what they'll notice: marked patrols, evenings, from March 1.","One number they'll use: the direct line.","SLAs reassure the property manager; faces and phone numbers reassure residents."],"focus":["audience","clarity"],"placeholder":"Starting March 1, you'll see our uniformed patrol in the complex every evening."},
    {"id":"audience-svc-senior-16","level":"senior","profession":"service","title":"RevPAR for a tech-world owner","scenario":"Your hotel's new majority owner made his money in software and keeps nodding politely at RevPAR and ADR. You're writing his first monthly summary. He thinks fluently in one frame: recurring revenue, unit economics, churn.","task":"Write a 3-4 sentence performance summary translated into your owner's native frame.","tips":["Map his frame: rooms as capacity, occupancy as utilization, repeat guests as retention.","Keep one hotel term and define it in-line; drop the rest.","Meeting the reader's frame is faster than teaching yours."],"focus":["audience","clarity"]},
    {"id":"audience-svc-senior-17","level":"senior","profession":"service","title":"The delivery-window requirement","scenario":"Your produce vendor keeps delivering during lunch service, blocking the kitchen at its worst hour. Your draft complaint explains your kitchen's workflow at length. What the vendor's dispatcher needs is a requirement stated in their operational terms.","task":"Write a 2-3 sentence request the dispatcher can act on directly.","tips":["State the requirement as a window: deliveries between 7 and 10 a.m.","Give the one consequence that matters to them: refused deliveries after 11.","Your workflow explains the rule; the dispatcher just needs the rule."],"focus":["audience","precision"]},
    {"id":"audience-svc-senior-18","level":"senior","profession":"service","title":"The touring franchise prospect","scenario":"A prospective franchisee touring your top site asks, 'Honestly, how hard is this business?' He's leaving a corporate career and has read only the sales brochure. Too rosy misleads him; too grim isn't true either.","task":"Write a 3-4 sentence answer calibrated to what a first-time operator needs to hear.","tips":["Name the hardest true thing first — it builds trust for the rest.","Anchor difficulty in specifics: hours, staffing churn, the first-year curve.","Calibrate to his gap: corporate skills that transfer, and the ones that don't."],"focus":["audience","clarity"]},
    {"id":"audience-svc-senior-19","level":"senior","profession":"service","title":"The VP asks how the district is doing","scenario":"The regional VP catches you at a conference: 'How's your district?' You have six sites, each with a story. She has ninety seconds and thirty other districts. Your instinct is to walk through all six.","task":"Write the 3-sentence answer: district headline, the one risk, the one thing you need.","tips":["Aggregate first: the district number, not six site numbers.","One risk she'd want to hear from you before she hears it elsewhere.","End with an ask or a 'nothing needed' — VPs remember who wastes the walk."],"focus":["audience","concision"],"placeholder":"District's up 4% on last year with five of six sites on plan."},
    {"id":"audience-svc-senior-20","level":"senior","profession":"service","title":"The app rollout for a skeptic","scenario":"You're moving scheduling to an app. Your most experienced manager — 25 years, runs your best site, distrusts software after the last failed rollout — is the one you're writing to. Your generic announcement praises 'digital transformation'.","task":"Write a personal 3-4 sentence note that speaks to his actual objection.","tips":["Name the last rollout's failure honestly — pretending it didn't happen costs you the reader.","His stake: fewer 6 a.m. phone calls about shift swaps, stated concretely.","Offer the paper fallback for month one; a bridge beats a decree."],"focus":["audience","impact"]},
    {"id":"audience-svc-senior-21","level":"senior","profession":"service","title":"The water shutoff notice","scenario":"A main repair means no hot water in your hotel from 10 p.m. to 6 a.m. tonight. Your draft guest notice leads with the plumbing contractor's schedule. A guest cares about: can I shower, when, and what are you doing for me?","task":"Write a 3-4 sentence in-room notice answering the guest's three questions.","tips":["Their evening first: hot water until 10 p.m., back by 6 a.m.","The gesture (late checkout, breakfast credit) goes in the notice, not just at the desk.","Contractor logistics are your problem; don't make them the guest's reading."],"focus":["audience","concision"]},
    {"id":"audience-svc-senior-22","level":"senior","profession":"service","title":"The mystery-shop huddle","scenario":"The mystery-shop report scored your site 71, with greeting time and table checks as the weak spots. You're briefing the floor team in a five-minute pre-shift huddle. Your draft reads the report's category scores aloud.","task":"Write a 3-4 sentence huddle brief that turns the report into two behaviors for tonight.","tips":["Staff can't act on '71' — they can act on 'greet within 30 seconds'.","Two behaviors maximum; a huddle isn't a training day.","Name what was strong so the ask lands as a tune-up, not a verdict."],"focus":["audience","impact"],"placeholder":"Two things tonight, both from the shop report: greet every table within 30 seconds, and check back within two minutes of food landing."},
    {"id":"audience-svc-senior-23","level":"senior","profession":"service","title":"One email, two audiences","scenario":"The parking lot is being repaved next week. You've drafted one email addressed to both the landlord (who's paying and wants minimal fuss) and your staff (who need to know where to park). It serves neither reader.","task":"Choose the staff as your audience and write their 2-3 sentence version.","tips":["One primary audience per message — split the email.","Staff version: dates, where to park instead, who to ask.","Everything written for the landlord is noise to a server on shift."],"focus":["audience","clarity"]},
    {"id":"audience-svc-senior-24","level":"senior","profession":"service","title":"The cash dip for the accountant","scenario":"Your accountant flagged an unusual cash dip in March and asked for context for the file. Your draft is a long defensive narrative. She needs the components: what hit, how much each, one-time or recurring.","task":"Write a 3-4 sentence explanation structured the way an accountant will file it.","tips":["Itemize: three drivers, a dollar figure each.","Label each one-time or recurring — that's the question behind the question.","She's not judging you; she's documenting. Write for the file."],"focus":["audience","precision"]},
    {"id":"audience-svc-senior-25","level":"senior","profession":"service","title":"The January dip, banker's frame","scenario":"Your banker sees January's numbers and emails a concerned question. January is always your worst month — the pattern is visible across three years — but your draft reply reads like an excuse. In her frame, the question is covenant headroom, not hurt feelings.","task":"Write a 3-4 sentence reply that reframes January in the banker's terms: seasonality, covered obligations, full-year track.","tips":["Lead with the reassurance her file needs: obligations covered through the dip, with headroom.","Show the pattern: three Januaries, same shape, same recovery.","'It's seasonal' is a claim; three years of data is an answer."],"focus":["audience","precision"],"placeholder":"January is our seasonal low — the same dip has appeared each of the last three years — and the line comfortably covers it:"}
  ],
  "structure-that-carries": [
    {"id":"structure-svc-senior-01","level":"senior","profession":"service","title":"Twelve metrics, one idea","scenario":"Your monthly review for the owner covers twelve metrics across five sites, and last month's version was twelve disconnected paragraphs. Looking at the data, one idea actually explains the month: the two sites with new managers drove all the underperformance.","task":"Write the governing idea as one sentence, then name the 3 buckets of evidence beneath it.","tips":["The governing idea is a claim, not a topic — 'new-manager sites drove the miss', not 'site performance'.","Every bucket must support the idea; orphan metrics go to an appendix.","If the owner reads only the first sentence, they should know what happened."],"focus":["structure","clarity"],"placeholder":"One thing explains the month: our two newest managers' sites drove the entire shortfall."},
    {"id":"structure-svc-senior-02","level":"senior","profession":"service","title":"SCQA for the lease memo","scenario":"You're writing the owner a memo recommending you renegotiate the flagship lease now, two years before expiry, while the landlord has vacancies on the street. Your draft opens with the recommendation but never builds the situation-complication logic that makes it obviously right.","task":"Write the memo's opening in SCQA form: Situation, Complication, Question, Answer — one sentence each.","tips":["Situation: the stable fact both of you agree on (lease runs to 2028).","Complication: what changed (three vacancies on the block, landlord exposed).","The answer should feel inevitable once S and C are laid out."],"focus":["structure","impact"]},
    {"id":"structure-svc-senior-03","level":"senior","profession":"service","title":"PREP on the ops call","scenario":"On the weekly ops call the director asks you cold: 'Should we extend evening hours at your mall locations for the holidays?' You have a view but tend to think aloud, touring the pros and cons before landing anywhere.","task":"Write your spoken answer in PREP form — Point, Reason, Example, Point — in 4-5 sentences.","tips":["Point first: yes, at two of the three, from Dec 1.","One reason with a number, one concrete example from last year.","Restate the point at the end so the answer has a floor and a ceiling."],"focus":["structure","clarity"],"placeholder":"Yes — but only at Fairview and Central, starting December 1. Here's why:"},
    {"id":"structure-svc-senior-04","level":"senior","profession":"service","title":"The site-visit brain dump","scenario":"You visited four sites this week and your notes are a mess: broken door closer, a star hire at Riverside, expired signage, a scheduling conflict, a walk-in running warm, two managers asking about bonuses, a supplier substituting brands. You're writing it up for yourself and the owner.","task":"Group the list into 3 labeled buckets and write one summary sentence for each.","tips":["Group by what the reader does: fix now, decide, celebrate/note.","The bucket label should be a claim ('Two safety items need money this week'), not a category ('Maintenance').","Anything that fits no bucket is a separate note, not a fourth bucket."],"focus":["structure","concision"]},
    {"id":"structure-svc-senior-05","level":"senior","profession":"service","title":"The turnaround plan skeleton","scenario":"Your Westgate location has missed plan for five straight months and the owner wants a turnaround plan. You have fifteen ideas. A plan with fifteen ideas is a list, not a plan — you need one governing idea and no more than three workstreams.","task":"Write the plan's governing idea and its 3 workstreams, one sentence each.","tips":["The governing idea names the root cause and the bet: 'Westgate's problem is management, not market.'","Each workstream gets an owner and a date in its sentence.","Ideas that don't serve the governing idea are cut, not appended."],"focus":["structure","impact"],"placeholder":"Westgate's problem is leadership and standards, not the market — so the plan has three parts:"},
    {"id":"structure-svc-senior-06","level":"senior","profession":"service","title":"The incident report that carries","scenario":"A contractor's ladder fell in your hotel lobby and grazed a guest. Head office needs the incident report. Your draft is chronological — a diary of the day — which forces the reader to assemble the meaning themselves.","task":"Restructure the report into four labeled parts — what happened, impact, cause, fix — one or two sentences each.","tips":["Lead each section with its conclusion, then the detail.","Keep cause and fix separate — mixing them muddies accountability.","A reader skimming the four bold labels should get the whole story."],"focus":["structure","precision"]},
    {"id":"structure-svc-senior-07","level":"senior","profession":"service","title":"The budget narrative in three buckets","scenario":"Your annual budget narrative to head office currently walks all forty line items in order. The reality has a shape: costs you've held flat, the two lines driving the increase, and one investment you're proposing.","task":"Write the narrative's opening: one governing sentence, then the 3 buckets with a sentence each.","tips":["The shape of the money is the structure — not the order of the spreadsheet rows.","Governing sentence carries the total and the single biggest driver.","Forty rows are the appendix; three buckets are the argument."],"focus":["structure","clarity"]},
    {"id":"structure-svc-senior-08","level":"senior","profession":"service","title":"Town-hall talking points","scenario":"You're addressing all staff across your cleaning company after a strong but turbulent year — growth, a lost major client, and a new pay structure. Your drafted remarks wander among the three topics and double back twice.","task":"Write the signposted opening: one framing sentence plus the 3 points you'll cover, announced in order.","tips":["Announce the map: 'Three things tonight: the year, the client we lost, and pay.'","Order deliberately — end on the point you want the room to carry home.","Signposting isn't padding; it's what lets a listener relax and follow."],"focus":["structure","audience"],"placeholder":"I want to cover three things tonight: the year we just had, the client we lost, and what's changing in pay."},
    {"id":"structure-svc-senior-09","level":"senior","profession":"service","title":"SCQA for the new site","scenario":"You're proposing a fourth salon to head office. Your draft leads with the opportunity — the new development, the demographics — but never establishes why now, or what happens if you wait. It reads as enthusiasm, not logic.","task":"Write the proposal opening in SCQA form, one sentence per element.","tips":["Situation: the trend they already accept (three sites at capacity).","Complication: the forcing event (anchor space leases in 90 days, competitor circling).","When SCQA is right, the reader asks your question before you pose it."],"focus":["structure","impact"]},
    {"id":"structure-svc-senior-10","level":"senior","profession":"service","title":"The manager-meeting agenda","scenario":"Your monthly managers' meeting agenda is a flat list of nine items, and the meeting always runs long with the decisions crowded into the last ten minutes. The items are actually three kinds: decisions needed, updates to hear, and one discussion topic.","task":"Rewrite the agenda grouped by type — decisions first — with a time box per group.","tips":["Decisions go first, while energy is highest.","Label each item with the verb: decide, hear, discuss.","An agenda is a structure for attention, not a list of topics."],"focus":["structure","concision"]},
    {"id":"structure-svc-senior-11","level":"senior","profession":"service","title":"PREP: why food cost is up","scenario":"The owner calls: 'Why is food cost up two points?' You know the answer — a supplier price increase you've partially offset, plus waste at one site — but under a direct question you tend to open with the site's staffing saga.","task":"Write the spoken PREP answer in 4 sentences: point, reason with numbers, example, point restated.","tips":["Point: 'Two causes, and one is already fixed.'","The example makes it concrete: the specific supplier item, the specific site.","Restating the point stops the answer from trailing into new topics."],"focus":["structure","precision"],"placeholder":"Two things: a dairy price increase we've half-offset, and waste at Mill Road that we've now fixed."},
    {"id":"structure-svc-senior-12","level":"senior","profession":"service","title":"The vacation handover","scenario":"You're away for two weeks and your deputy covers the district. Your handover draft is a chronological tour of everything on your plate. What the deputy needs is a structure: must act, must watch, and context only.","task":"Write the handover's skeleton — 3 labeled sections with the top item in each.","tips":["'Must act' items carry a date and a name.","'Watch' means a trigger: 'if X happens, do Y'.","Context that drives no action goes last or gets cut — it's your comfort, not their need."],"focus":["structure","clarity"]},
    {"id":"structure-svc-senior-13","level":"senior","profession":"service","title":"The RFP evaluation summary","scenario":"You evaluated three security-equipment vendors against six criteria and your summary for the owner is a dense comparison table with no verdict. The owner will ask: which one, and on what basis?","task":"Write the summary's opening: recommendation first, then the 3 criteria that decided it, one sentence each.","tips":["The recommendation is the governing idea; criteria are the buckets beneath it.","Three deciding criteria, not six — the others tied or didn't matter.","The table survives as backup for whoever wants to audit the call."],"focus":["structure","clarity"]},
    {"id":"structure-svc-senior-14","level":"senior","profession":"service","title":"Fourteen complaints, three themes","scenario":"Head office forwarded fourteen customer complaints from your Bayview location this quarter and asked what's going on. Read together, they cluster: nine about wait times, three about one staff member, two one-offs. Your draft answers them one by one.","task":"Write a 3-4 sentence reply organized by theme, leading with the dominant one.","tips":["Group before you answer — fourteen answers is no answer.","Lead with the theme that explains nine of fourteen, and its fix.","Name the outliers as outliers so they don't read as dodged."],"focus":["structure","precision"],"placeholder":"The fourteen complaints are really three issues, and one dominates: nine are wait times at Friday dinner."},
    {"id":"structure-svc-senior-15","level":"senior","profession":"service","title":"SCQA for the delivery pilot","scenario":"You want the franchisor to let two of your sites pilot third-party delivery, which the brand has resisted. Your draft argues the upside at length. The persuasive structure is SCQA: the situation they accept, the complication in the data, the question it forces.","task":"Write the pitch opening in SCQA form, one sentence each.","tips":["Situation: dine-in traffic pattern the franchisor already reports on.","Complication: the delivery-only competitor's growth in your postal codes.","Frame the answer as a bounded pilot — structure can shrink perceived risk."],"focus":["structure","impact"]},
    {"id":"structure-svc-senior-16","level":"senior","profession":"service","title":"The investor letter's spine","scenario":"Your annual letter to the three investors in your hotel runs six pages and covers everything. Six pages with no spine reads as evasion even when the news is good. This year's true story: the renovation bet paid off.","task":"Write the letter's governing idea as one sentence and the 3 section headers that hang from it.","tips":["The governing idea is the sentence they'd repeat to a spouse: 'The renovation paid for itself in year one.'","Every section header should restate part of the proof, not name a topic.","Length is fine when structure carries it; deadly when it doesn't."],"focus":["structure","impact"]},
    {"id":"structure-svc-senior-17","level":"senior","profession":"service","title":"The training-program pitch","scenario":"You want the owner to fund a supervisor-training program across the chain. Your draft is a feature tour of the curriculum. The persuasive order is: the problem and its cost, the plan, the return.","task":"Write the pitch in 3 labeled moves — problem with its cost, plan, return — one or two sentences each.","tips":["The problem's price tag comes first: turnover and failed audits in dollars.","The plan is one sentence; the curriculum detail is an attachment.","End with return and a date: what improves, by when, measured how."],"focus":["structure","impact"],"placeholder":"Supervisor turnover cost us roughly $80k last year — this is a plan to cut it in half."},
    {"id":"structure-svc-senior-18","level":"senior","profession":"service","title":"PREP for the bank meeting","scenario":"In the loan renewal meeting the banker asks, 'How will you repay this if the anchor client leaves?' You have a real answer — client concentration is down and the contract has an 18-month term — but nerves scatter your structure.","task":"Write the spoken PREP answer in 4-5 sentences.","tips":["Point first: 'Repayment doesn't depend on that client.'","Reason with numbers: their share of revenue then vs. now.","Example: the client you already replaced last year.","Land the point again — banks remember conclusions, not tours."],"focus":["structure","precision"]},
    {"id":"structure-svc-senior-19","level":"senior","profession":"service","title":"Audit findings, triaged","scenario":"The franchisor audit left your site manager a nine-item findings list, and she's treating all nine as equally urgent — which means none gets done well. The findings actually triage: two fix-now, four fix-this-month, three systemic.","task":"Write her a message that regroups the nine findings into the 3 triage buckets with a deadline per bucket.","tips":["The bucket structure is the instruction — it tells her where today goes.","Fix-now items get named individually; the rest can be counted.","Systemic items need a different verb: not 'fix' but 'redesign', with your involvement."],"focus":["structure","clarity"]},
    {"id":"structure-svc-senior-20","level":"senior","profession":"service","title":"One idea per slide","scenario":"Your annual review deck for head office has slides titled 'Revenue', 'Labor', 'Sites', 'Outlook' — topics, not claims. The reviewer flips through wondering what you're actually saying. Each slide title should be the sentence you'd say if you had only that slide.","task":"Rewrite the four slide titles as full-sentence claims that together tell the year's story.","tips":["A title like 'Labor' hides the news; 'Labor costs held flat despite the wage increase' is the news.","Read the four titles aloud in order — they should work as a paragraph.","If a slide's content doesn't prove its title-claim, fix one or the other."],"focus":["structure","clarity"],"placeholder":"Slide 1: The district grew 6% while the market was flat."},
    {"id":"structure-svc-senior-21","level":"senior","profession":"service","title":"State of the district, post-acquisition","scenario":"Your group just absorbed two struggling sites from a retiring operator, taking you from five to seven. Your first all-managers email about the new shape of the district is drafted as a timeline of the deal. The managers need the new picture, not the history.","task":"Write the email's structure: one governing sentence about the new district, then 3 sections — what's new, what doesn't change, what happens next.","tips":["'What doesn't change' is a load-bearing section — it kills the rumor mill.","'What happens next' needs dates, even rough ones.","The deal timeline interests you; the new org chart interests them."],"focus":["structure","audience"]},
    {"id":"structure-svc-senior-22","level":"senior","profession":"service","title":"The year-end review, themed","scenario":"You're writing a site manager's annual review and your notes are forty scattered observations from twelve months. Read together they make three themes: operational excellence, a hiring blind spot, and untapped commercial instinct.","task":"Write the review's opening: overall verdict in one sentence, then the 3 themes announced.","tips":["Forty observations exhaust; three themes teach.","Each theme should pair evidence with trajectory — where this goes next year.","The verdict sentence sets the frame; don't let theme two contradict it by surprise."],"focus":["structure","clarity"]},
    {"id":"structure-svc-senior-23","level":"senior","profession":"service","title":"SCQA for closing the kiosk","scenario":"The mall kiosk was your experiment and it hasn't worked. You're recommending closure to your business partner, who championed it. A bare recommendation will read as an attack; SCQA lets the logic do the work.","task":"Write the closure case in SCQA form, one sentence per element.","tips":["Situation: what you both believed when you opened it — stated fairly.","Complication: what the eighteen months of data showed instead.","When S honors the original bet, the A stops being personal."],"focus":["structure","impact"],"placeholder":"When we opened the kiosk we bet foot traffic would convert at 3% — that was reasonable at the time."},
    {"id":"structure-svc-senior-24","level":"senior","profession":"service","title":"Year two, out loud","scenario":"A new investor over dinner asks, 'So what's the plan for year two?' You have a real plan but it lives in a spreadsheet. Spoken, it needs PREP: the headline bet, why it's the right one, the proof point, the headline again.","task":"Write the 4-5 sentence spoken answer in PREP form.","tips":["The point is the bet: 'Year two is about margin, not new sites.'","One reason, one example — dinner-table answers can't hold more.","If your answer has no single point, you've found the real problem: the plan doesn't either."],"focus":["structure","concision"]},
    {"id":"structure-svc-senior-25","level":"senior","profession":"service","title":"The winter-readiness memo, rebuilt","scenario":"Your twelve-paragraph winter-readiness memo to all site managers mixes heating checks, salt contracts, staffing for storm days, and pipe insulation in no order. Managers keep calling to ask what applies to them. The content is fine; the structure is absent.","task":"Rebuild it as a pyramid: one governing sentence, then 3 grouped sections with their headers.","tips":["Group by the reader's action: check by Nov 1, contract by Nov 15, plan for storm days.","Headers should carry deadlines — that's what the callers keep asking.","Twelve paragraphs under three claims is a memo; twelve loose paragraphs is a phone tree."],"focus":["structure","clarity"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-svc-senior-01","level":"senior","profession":"service","title":"The 200-word memo, halved","scenario":"Your memo to managers about the new schedule-posting rule runs 200 words: a warm preamble, the rule, three restatements of the rule, and a soft closing. The rule itself is one sentence.","task":"Rewrite the memo in under 60 words without losing the rule, the date, or the consequence.","tips":["State the rule once, precisely — restatement signals doubt, not emphasis.","Cut the preamble; the subject line does that job.","Keep the consequence: it's the only sentence that changes behavior."],"focus":["concision","clarity"]},
    {"id":"concise-svc-senior-02","level":"senior","profession":"service","title":"De-hedging the rent email","scenario":"Your draft to the landlord reads: 'I was just wondering if perhaps there might be some possibility of discussing a potential adjustment to the rent, if that's something you'd be open to considering.' Thirty words, zero commitment.","task":"Rewrite the sentence as a direct request in under 15 words.","tips":["One hedge maximum — 'I'd like to discuss' is already polite.","'Just', 'perhaps', 'might', 'potential' stack into a whisper.","Directness reads as confidence, and landlords negotiate with confidence."],"focus":["concision","impact"],"placeholder":"I'd like to discuss reducing the rent for the construction period."},
    {"id":"concise-svc-senior-03","level":"senior","profession":"service","title":"Killing the meta-commentary","scenario":"Your ops report is padded with scaffolding: 'In this section I will describe...', 'As mentioned above...', 'It should be noted that...', 'Before turning to labor, it is worth pausing on...'. A quarter of the report is the report talking about itself.","task":"Take three of those scaffold sentences and rewrite each as its actual content or delete it.","tips":["'It should be noted that sales fell' is just 'Sales fell.'","If a sentence describes the document instead of the business, cut it.","Headers do the navigating; sentences should carry news."],"focus":["concision","clarity"]},
    {"id":"concise-svc-senior-04","level":"senior","profession":"service","title":"Redundant pairs in the SOP","scenario":"Your new opening-procedures SOP is infected with pairs: 'each and every station', 'first and foremost', 'basic and fundamental checks', 'full and complete inventory'. Staff read SOPs at 6 a.m.; every extra word costs compliance.","task":"Rewrite two SOP sentences, collapsing every redundant pair to one word.","tips":["English pairs sound formal but say nothing twice: pick one.","An SOP is read under time pressure — write for the 6 a.m. brain.","Test: does deleting one half of the pair change the instruction? Then delete it."],"focus":["concision","precision"]},
    {"id":"concise-svc-senior-05","level":"senior","profession":"service","title":"Un-nominalizing the incident report","scenario":"Your incident report says: 'A review of the footage was conducted and a determination was made that the implementation of corrective measures would be undertaken.' Every verb has been buried in a noun.","task":"Rewrite the sentence with people doing things, in under 15 words.","tips":["'Conducted a review' is 'reviewed'; 'made a determination' is 'decided'.","Nominalizations hide the actor — say who reviewed and who will fix.","Buried verbs read as evasion in an incident report, exactly where you can't afford it."],"focus":["concision","clarity"],"placeholder":"I reviewed the footage and we will retrain the evening team by Friday."},
    {"id":"concise-svc-senior-06","level":"senior","profession":"service","title":"The review reply, cut to two lines","scenario":"A guest left a fair 3-star review about slow Sunday service. Your drafted reply runs six lines: apology, explanation of the staffing situation, another apology, a defense, an invitation, a sign-off paragraph. Future customers read these replies more than the reviewer does.","task":"Rewrite the reply in 2 sentences: acknowledgment with the fix, and the invitation.","tips":["One apology; the second reads as groveling and the defense erases both.","Name the fix concretely — that's what future readers are scanning for.","Staffing explanations are internal; the reader just needs 'we fixed it'."],"focus":["concision","audience"]},
    {"id":"concise-svc-senior-07","level":"senior","profession":"service","title":"The 400-word job posting","scenario":"Your assistant-manager posting runs 400 words, half of it phrases like 'the successful candidate will demonstrate a proven ability to' and a duty list that includes 'other duties as assigned'. Strong candidates skim and bounce.","task":"Cut the posting to under 120 words that still say the role, the pay, the site, and the one thing that makes it worth taking.","tips":["'Proven ability to demonstrate' constructions collapse to a verb.","Pay and site are decision information — never cut those to save words.","One genuine selling line beats five boilerplate ones."],"focus":["concision","audience"]},
    {"id":"concise-svc-senior-08","level":"senior","profession":"service","title":"The apology without the groveling","scenario":"Your cleaning crew missed a scheduled office service and the client noticed. Your draft apology is nine sentences, six of them variations of how sorry you are and how this isn't who you are. The client wants: acknowledgment, cause, fix, remedy.","task":"Rewrite the apology in 4 sentences — one each for acknowledgment, cause, fix, and remedy.","tips":["Apologize once, specifically: 'we missed Thursday's service' beats 'any inconvenience'.","Cause in one honest clause — no saga.","The remedy sentence (credit, redo) is the one they'll remember."],"focus":["concision","impact"],"placeholder":"We missed your Thursday service, and I'm sorry — that's on us."},
    {"id":"concise-svc-senior-09","level":"senior","profession":"service","title":"The meeting invite with a buried purpose","scenario":"Your calendar invite to three managers reads: 'Wanted to get some time on the books to connect and align on a few things regarding the upcoming season and some staffing considerations we should probably talk through.' Nobody can prepare for that meeting.","task":"Rewrite the invite body in 2 sentences: the decision the meeting exists to make, and what to bring.","tips":["A meeting has a purpose or it has a mood — write the purpose.","'Connect and align' is mood; 'decide holiday staffing at both mall sites' is purpose.","Say what to bring; preparation is the cheapest meeting-shortener there is."],"focus":["concision","clarity"]},
    {"id":"concise-svc-senior-10","level":"senior","profession":"service","title":"The one-page summary, halved again","scenario":"You got the Westgate turnaround summary down to one page and you're proud of it. The owner reads on his phone between site visits. One page is still twice too long — the plan has three moves and a number.","task":"Cut the one-pager to 5 sentences that survive a phone screen.","tips":["Each workstream gets one sentence with its owner and date.","The financial ask and the payback number cannot be cut; almost everything else can.","Write for the reader's actual reading conditions, not the document's dignity."],"focus":["concision","structure"]},
    {"id":"concise-svc-senior-11","level":"senior","profession":"service","title":"The throat-clearing call opener","scenario":"You open the weekly ops call the same way every time: 'Okay so, thanks everyone for hopping on, I know everyone's busy, there's a lot going on this week, we've got a bunch to get through, so I guess without further ado...' Forty words before content.","task":"Write a spoken opening of 2 sentences that starts the meeting inside ten seconds.","tips":["First sentence: the meeting's headline or its first decision.","Thanking people for attending a mandatory call is filler with manners.","The opener trains the room: start with substance and they arrive ready."],"focus":["concision","impact"],"placeholder":"Morning — three items today, and the first one's a decision:"},
    {"id":"concise-svc-senior-12","level":"senior","profession":"service","title":"The vendor complaint, 8 to 3","scenario":"Your draft email to the produce vendor about repeated short deliveries runs eight sentences, weaving the complaint with reassurances that you value the relationship. The complaint has three parts: the pattern, the cost, the requirement.","task":"Rewrite the email in 3 sentences: pattern with dates, cost, requirement with deadline.","tips":["Relationship reassurance dilutes a complaint — one closing clause is plenty.","Dates make a pattern; 'repeatedly' makes an opinion.","End with the requirement, not an open question."],"focus":["concision","precision"]},
    {"id":"concise-svc-senior-13","level":"senior","profession":"service","title":"De-legalesing the policy note","scenario":"Your draft policy note reads: 'Effective as of the first of the month, all personnel shall be required to ensure that closing procedures are executed in accordance with the updated checklist heretofore distributed.' Staff will not read it twice.","task":"Rewrite the policy in one plain sentence.","tips":["'Shall be required to ensure that... are executed' is 'must follow'.","Legalese borrows authority; plain language carries it.","If a 19-year-old closer can't repeat the rule after one read, rewrite it."],"focus":["concision","clarity"],"placeholder":"From March 1, closers must follow the new checklist."},
    {"id":"concise-svc-senior-14","level":"senior","profession":"service","title":"Cutting 'I think' from the recommendation","scenario":"Your recommendation email to head office contains: 'I think we should probably consider maybe consolidating the two underperforming sites, in my opinion.' Four hedges around one verb. You've run these sites for six years; you're the expert in the room.","task":"Rewrite the sentence with at most one qualifier.","tips":["'I recommend' carries your judgment without apologizing for it.","One honest qualifier ('pending the lease review') beats four reflexive ones.","Hedging your expertise makes the reader supply their own doubt."],"focus":["concision","impact"]},
    {"id":"concise-svc-senior-15","level":"senior","profession":"service","title":"Five texts into one","scenario":"You sent a site manager five texts in a row: a thought, a correction to the thought, an additional item, a 'sorry, one more thing', and a clarification. She's mid-shift. The five messages contain exactly two asks and one date.","task":"Write the single message you should have sent, under 40 words.","tips":["Draft in your notes app; send once.","Two asks, one date, numbered if needed.","Every extra ping spends the recipient's attention — the scarcest thing on a shift."],"focus":["concision","clarity"]},
    {"id":"concise-svc-senior-16","level":"senior","profession":"service","title":"The 300-word executive summary","scenario":"The executive summary of your budget runs 300 words — a summary that needs its own summary. Head office reads twelve of these in a sitting. Yours must land the total, the change, the driver, and the ask in one breath.","task":"Cut the summary to under 80 words without losing a number the reader needs.","tips":["Numbers survive the cut; adjectives don't.","One sentence per job: total, change and driver, ask, risk.","A summary earns its name at the length a reader holds in working memory."],"focus":["concision","precision"],"placeholder":"FY budget: $1.2M opex, up 4% — driven entirely by the wage floor. Requesting approval by March 15."},
    {"id":"concise-svc-senior-17","level":"senior","profession":"service","title":"The 500-word 'quick update'","scenario":"Your message to the owner opens with 'Quick update —' and runs 500 words across the freezer repair, two hiring updates, a lease note, and the weekend's sales. Nothing in it is unimportant, but nothing in it can be found either.","task":"Rewrite it as a genuinely quick update: a headline sentence plus 4 one-line bullets.","tips":["If it says quick, make it quick — or retitle it.","One line per topic; anything needing more becomes its own message.","Bold or lead with the one item that needs the owner's action."],"focus":["concision","structure"]},
    {"id":"concise-svc-senior-18","level":"senior","profession":"service","title":"The elevator-outage sign","scenario":"The hotel elevator is out until Thursday. Your drafted lobby sign is five sentences, including an explanation of elevator maintenance cycles and two apologies. A guest with a suitcase reads signs for exactly three seconds.","task":"Write the sign in under 20 words: what, until when, what to do instead, and where to get help.","tips":["Signs are scanned, not read — front-load the noun.","One apology word maximum; the help offer is the real courtesy.","The maintenance-cycle explanation serves you, not the guest with the bag."],"focus":["concision","audience"],"placeholder":"Elevator out until Thursday. Stairs are to your left — call the desk to have bags carried up."},
    {"id":"concise-svc-senior-19","level":"senior","profession":"service","title":"The training memo's warm-up lap","scenario":"Your memo announcing mandatory food-safety refreshers opens with three sentences about the importance of training, the company's commitment to excellence, and the evolving regulatory landscape. The actual news — two-hour session, three dates to pick from — starts in paragraph two.","task":"Delete the warm-up and write the memo in 3 sentences starting with the news.","tips":["Commitment-to-excellence prose is skipped by every reader, every time.","News first: what, how long, which dates, how to sign up.","One sentence of why is plenty when the why is obvious."],"focus":["concision","clarity"]},
    {"id":"concise-svc-senior-20","level":"senior","profession":"service","title":"Phrase-level flab in the incident notice","scenario":"Your incident notice to head office includes 'at this point in time', 'in the event that', 'due to the fact that', 'in the process of conducting', and 'on a going-forward basis'. Each phrase has a one-word replacement.","task":"Rewrite two sentences from the notice, replacing every flab phrase with its short form.","tips":["'At this point in time' is 'now'; 'in the event that' is 'if'.","Flab phrases cluster under stress — incident writing needs the opposite.","Shorter sentences read as more in control, which is the message an incident notice sends."],"focus":["concision","precision"]},
    {"id":"concise-svc-senior-21","level":"senior","profession":"service","title":"The thread, summarized","scenario":"A 30-message email thread about the Riverside patio permit has been forwarded to the owner with 'see below'. Nobody should have to read below. The thread's content: permit approved with two conditions, contractor booked, one open question about insurance.","task":"Write the 3-sentence summary that should replace 'see below'.","tips":["Forwarding a thread is delegating your job to the reader.","Status, conditions, and the one open question — that's the whole thread.","Name who owns the open question so the summary ends in motion."],"focus":["concision","structure"],"placeholder":"Patio permit approved with two conditions. Where it stands:"},
    {"id":"concise-svc-senior-22","level":"senior","profession":"service","title":"The investor update, halved","scenario":"Your quarterly investor update runs two pages. The quarter's story is simple: revenue up 5%, one site struggled, you've replaced its manager, cash is fine. Investors with three other holdings give it ninety seconds.","task":"Cut the update to 6 sentences that keep every number and lose every digression.","tips":["Every sentence must carry a fact they'd act on or remember.","The struggling site gets two sentences: the miss and the fix — not a defense.","Ending on cash position is ending on the answer to their unasked question."],"focus":["concision","impact"]},
    {"id":"concise-svc-senior-23","level":"senior","profession":"service","title":"The 30-second voicemail","scenario":"You need to leave the landlord a voicemail about the June 1 lease decision. Unrehearsed, your voicemails ramble past a minute and bury the callback request. You have three things to say: decision coming, one question about the escalation clause, call back by Friday.","task":"Write the voicemail script in under 60 words.","tips":["Name and number in the first five seconds and again at the end.","One question per voicemail — a second question halves the callback rate.","Write it before you dial; nobody improvises concisely."],"focus":["concision","clarity"]},
    {"id":"concise-svc-senior-24","level":"senior","profession":"service","title":"The handbook paragraph","scenario":"A handbook paragraph on shift swaps runs 90 words with three subordinate clauses and a parenthetical exception. New hires read it during a fifteen-minute onboarding. The rule: swaps need manager approval 24 hours ahead, except emergencies, which need a call.","task":"Rewrite the rule in 2 short sentences a new hire retains after one read.","tips":["Rule first, exception second — never interleaved.","Subordinate clauses in rules become loopholes in practice.","If the rule can't be recited from memory, it isn't a rule yet."],"focus":["concision","clarity"],"placeholder":"Shift swaps need your manager's OK at least 24 hours ahead. Real emergency? Call your manager."},
    {"id":"concise-svc-senior-25","level":"senior","profession":"service","title":"The all-hands announcement, tightened","scenario":"You're announcing the year's results at the staff party across all sites. Your draft runs two minutes: a tour of every quarter, three metaphors, and thank-yous that name eleven people. The room is standing, holding drinks.","task":"Cut it to 4 spoken sentences: the result, what it took, one specific thank-you, what's next.","tips":["A standing audience gives you thirty seconds — design for it.","One vivid specific ('we served 212,000 guests') beats three metaphors.","Thank the group and one story, not a list — lists exclude whoever's twelfth."],"focus":["concision","impact"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-svc-senior-01","level":"senior","profession":"service","title":"'Significantly better' at the owner review","scenario":"Your quarterly summary tells the owner that Riverside is doing 'significantly better' since Dana took over as GM. He asks what significantly means, and you don't have the figure to hand. Vague intensifiers invite exactly this question.","task":"Rewrite the claim with the number, the baseline, and the period.","tips":["Replace 'significantly' with the percentage and the from-to.","Name the period so the claim is checkable.","A number pre-empts the follow-up; an adverb invites it."],"focus":["precision","clarity"],"placeholder":"Riverside's sales are up 11% in Dana's first eight weeks — $86k a month against $77.5k before."},
    {"id":"precision-svc-senior-02","level":"senior","profession":"service","title":"'Soon' won't book a party","scenario":"The kitchen rebuild is nearly done and your events coordinator asks when she can start taking December bookings. Your reply says the restaurant reopens 'soon' and full service resumes 'shortly after'. She can't sell soon.","task":"Rewrite the reply replacing every vague time word with a date.","tips":["'Soon' and 'shortly' are unusable for anyone planning around you.","If a date isn't certain, give the date plus your confidence.","Every adverb of time in a business message is a dodged commitment."],"focus":["precision","clarity"],"placeholder":"We reopen Tuesday the 12th; full menu from the 19th. Book December from the 19th onward."},
    {"id":"precision-svc-senior-03","level":"senior","profession":"service","title":"'A lot of overtime' to head office","scenario":"Your district update says the sites have been running 'a lot of overtime' since two supervisors left. Head office can't budget, plan, or approve anything against 'a lot'. You have the payroll export open in the next tab.","task":"Rewrite the sentence with hours, dollars, and the sites affected.","tips":["'A lot' is invisible to a finance reader — quantify it.","Tie hours to dollars; dollars are the language of approval.","Name which sites, so the number becomes a plan."],"focus":["precision","impact"],"placeholder":"Eastside and Mill Road ran 210 overtime hours last month — $6,400 over plan — covering the two open supervisor roles."},
    {"id":"precision-svc-senior-04","level":"senior","profession":"service","title":"The skeptic test on the patio payback","scenario":"You're telling the owner the new patio 'pays for itself in one summer'. He will attack that number, and right now it's a round claim with no build. If it can't survive his three questions, it can't get funded.","task":"State the payback claim with its two or three components, each quantified.","tips":["Break the round number into its sources: seats, covers, average check.","Name the assumption most likely to be challenged — weather, season length — and bound it.","A number that survives the skeptic is a number that gets built."],"focus":["precision","structure"],"placeholder":"The patio costs $38k and returns roughly $41k in one season: 24 seats, 1.5 turns on 90 fair-weather days, at our $28 average check."},
    {"id":"precision-svc-senior-05","level":"senior","profession":"service","title":"'Reviews are way up'","scenario":"Your note to the franchisor says online reviews at Elm Street are 'way up' since the retraining. The field consultant scores sites on evidence, not enthusiasm. You have the ratings dashboard in front of you.","task":"Rewrite the claim with the rating from-to, the review count, and the window.","tips":["A rating move means nothing without the volume behind it.","From-to beats a single number — the baseline is half the story.","Date the window so the claim connects to the retraining, not luck."],"focus":["precision","clarity"],"placeholder":"Elm Street's Google rating moved from 3.9 to 4.4 over the twelve weeks since retraining, across 212 new reviews."},
    {"id":"precision-svc-senior-06","level":"senior","profession":"service","title":"So what for the labor point","scenario":"Your report states that district labor cost fell from 31.2% to 30.0% of sales. True, and left as a bare fact. The owner needs the insight: what that 1.2 points is worth and what you're doing with it.","task":"Add the 'so what': translate the 1.2-point gain into dollars and a decision.","tips":["Data isn't insight until you say what it buys.","Convert points into annual dollars — that's the owner's currency.","End with whether it holds, and what the savings funds."],"focus":["precision","impact"],"placeholder":"Labor fell 1.2 points — about $58k a year at current sales — which covers the supervisor training program with room to spare."},
    {"id":"precision-svc-senior-07","level":"senior","profession":"service","title":"The complaint cluster's now-what","scenario":"Your complaint log shows 70% of this quarter's complaints came from Friday and Saturday dinner at two sites. You've reported the pattern twice and nothing has changed, because you stopped at the finding. The owner needs the action the data demands.","task":"Write three sentences: the finding, what it means, and the specific action with an owner and date.","tips":["What: where and when the complaints cluster.","So what: the pattern points at weekend staffing, not the menu.","Now what: the change, who owns it, and the date it starts."],"focus":["precision","structure"]},
    {"id":"precision-svc-senior-08","level":"senior","profession":"service","title":"'Often late' becomes a log","scenario":"Your complaint email to the linen vendor says deliveries are 'often late and frequently incomplete'. Their account manager will politely ask for examples, and 'often' will evaporate. Your receiving log has the real record.","task":"Rewrite the complaint with counts, dates, and the cost to you.","tips":["Dates make a pattern; 'often' makes an opinion.","Count both failures separately: late is one problem, short is another.","End with the cost — that's what makes a vendor move."],"focus":["precision","impact"],"placeholder":"Of the last 12 deliveries, 7 arrived after the 10 a.m. window and 4 were short — the shortages alone cost us $900 in emergency purchases."},
    {"id":"precision-svc-senior-09","level":"senior","profession":"service","title":"The evidence behind 'on track'","scenario":"You told head office the Lakeside opening is 'on track'. The regional VP replies with one line: 'On track against what?' You have the milestone plan and the spend sheet; the claim just never touched them.","task":"Restate 'on track' with two concrete evidence points — one schedule, one money.","tips":["'On track' needs a track: name the plan you're measuring against.","One milestone fact, one spend fact — that's a complete answer.","Evidence turns an assertion into a report."],"focus":["precision","structure"],"placeholder":"On track: five of six pre-opening milestones done, and build-out spend is $212k against a $230k budget."},
    {"id":"precision-svc-senior-10","level":"senior","profession":"service","title":"'People keep leaving'","scenario":"You're making the case for a wage review, and your draft says 'people keep leaving and it's getting hard to hire'. Head office hears that from every district. The claim needs the turnover rate, the benchmark, and the price tag.","task":"Rewrite the claim with your turnover rate, a comparison, and the annual cost.","tips":["'Keep leaving' is a mood; 64% annual turnover is a fact.","Compare to something — the brand average, last year, the market.","Cost per departure times departures is the number that wins budget."],"focus":["precision","impact"],"placeholder":"District turnover hit 64% this year against a brand average of 45% — at roughly $3,200 per replacement, that gap cost us $61k."},
    {"id":"precision-svc-senior-11","level":"senior","profession":"service","title":"Foot-traffic proof for the landlord","scenario":"You're asking the landlord for rent relief during the street reconstruction and he's skeptical that the impact is real. 'Business is way down' is your word against his lease. Your POS and the door counter can make it his problem too.","task":"Write 2-3 sentences stating the impact with checkable numbers a landlord would accept.","tips":["Use sources he can't dismiss: transaction counts, door counter, same period last year.","Percentages need a base — give the dollar figure too.","Evidence a skeptic would accept is evidence collected before you needed it."],"focus":["precision","audience"],"placeholder":"Since the roadwork began, weekday transactions are down 38% against the same eight weeks last year — 1,860 versus 3,010 — roughly $54k in lost sales."},
    {"id":"precision-svc-senior-12","level":"senior","profession":"service","title":"The claim file's numbers","scenario":"You're documenting the third-floor water damage for the insurer. Your draft says the leak 'took out a large section of the floor for a while, costing significant revenue'. Adjusters pay against specifics and discount everything else.","task":"Rewrite the loss statement with rooms, nights, and the rate math.","tips":["Rooms out, nights lost, average rate — the claim writes itself from those three.","'Significant' invites a low estimate; your number anchors the negotiation.","Attach the source (occupancy report) so the number arrives pre-verified."],"focus":["precision","audience"],"placeholder":"Eleven rooms were out of service for 9 nights — 99 room-nights at our $140 average rate, roughly $13,900 in lost revenue, per the attached occupancy report."},
    {"id":"precision-svc-senior-13","level":"senior","profession":"service","title":"'The team is stretched'","scenario":"You're warning the owner that service quality is at risk because 'the team is stretched thin'. He nods and moves on — he's heard 'stretched' every quarter for years. The staffing data says something sharper.","task":"Rewrite the warning with open roles, uncovered shifts, and what breaks first.","tips":["'Stretched' is wallpaper; '11 uncovered shifts next week' is an alarm.","Count the vacancies and name the roles.","Say what fails first — that converts sympathy into a decision."],"focus":["precision","impact"],"placeholder":"We're carrying 5 open roles across three sites and 11 uncovered shifts next week — the first thing that breaks is Friday dinner service at Bayview."},
    {"id":"precision-svc-senior-14","level":"senior","profession":"service","title":"Cost per cover, not 'expensive'","scenario":"Head office is questioning your local marketing spend as 'expensive'. Your defense draft argues that marketing 'clearly drives traffic'. Two vague claims are now fighting each other. You have the numbers to end the argument.","task":"Write a 2-3 sentence defense that prices the spend against what it returned.","tips":["Divide: spend over new covers gives cost per cover — one honest number.","Compare it to the margin a cover carries; the verdict falls out.","When both sides are vague, whoever brings a number first wins."],"focus":["precision","impact"],"placeholder":"The $2,400 campaign brought roughly 640 trackable new covers — $3.75 each against a $9 average margin per cover."},
    {"id":"precision-svc-senior-15","level":"senior","profession":"service","title":"'Customers love it' quantified","scenario":"You want to roll the new weekend brunch from one site to all six, and your pitch says 'customers love it'. The ops director has approved exactly zero rollouts on love. The pilot site has eight weeks of sales mix data.","task":"Rewrite the case with the numbers that prove demand.","tips":["Love shows up in data as repeat visits, mix share, and covers — pick two.","Eight weeks of pilot data beats any adjective.","State what the rollout needs so the evidence lands on a decision."],"focus":["precision","impact"],"placeholder":"In eight weeks, brunch grew to 22% of weekend sales at the pilot site, with covers up 31% — I'm asking to roll it to all six sites by June."},
    {"id":"precision-svc-senior-16","level":"senior","profession":"service","title":"The card-skimmer scope, precisely","scenario":"A payment terminal at one location was found with a skimming device. Your draft alert to the owner says 'some customer cards may have been compromised over recent weeks'. Legal, the bank, and the press response all depend on the exact scope.","task":"State the scope precisely: which terminal, what date range, how many transactions.","tips":["Precision limits both liability and panic — name the one terminal.","Give the confirmed date range from the service records.","A precise scope is a smaller, more manageable problem than a vague one."],"focus":["precision","clarity"],"placeholder":"One terminal — patio register at Central, installed to compromised between May 4 and May 19 — processed 1,240 card transactions in that window."},
    {"id":"precision-svc-senior-17","level":"senior","profession":"service","title":"Postal-code evidence for the delivery pitch","scenario":"You're pitching the franchisor on a delivery pilot and your draft says demand in your area is 'clearly moving to delivery'. The brand team has rejected 'clearly' from a dozen franchisees this year. You bought the market report; use it.","task":"Rewrite the demand claim with two specific data points from your trade area.","tips":["Local data beats national trends — it's your postal codes or nothing.","Two independent numbers corroborate; one can be dismissed.","Cite the source in-line so the skeptic's first question is pre-answered."],"focus":["precision","audience"],"placeholder":"In our three core postal codes, delivery orders in our category grew 41% year over year, and the delivery-only competitor added two kitchens within 3 km."},
    {"id":"precision-svc-senior-18","level":"senior","profession":"service","title":"The Sunday loss, built","scenario":"You've told the VP that Sunday service at Mill Road 'loses about $700 a week', and she wants the build before she'll approve closing the day. A round number with no components looks like a guess — even when it isn't.","task":"Break the $700 into its components in 2-3 sentences.","tips":["Show the arithmetic: revenue, prime costs, fixed allocation.","Say what's avoidable if you close and what isn't — that's the real decision number.","A built number invites a decision; a round one invites an audit."],"focus":["precision","structure"],"placeholder":"Sundays average $2,100 in sales against $2,800 in costs: $1,450 labor, $700 food, $650 allocated fixed. Closing avoids the first two — about $2,150 — for a true weekly saving near $650."},
    {"id":"precision-svc-senior-19","level":"senior","profession":"service","title":"'Business is strong' for the bank","scenario":"Your line-of-credit renewal letter opens with 'the business has never been stronger'. Your banker has read that sentence in a hundred renewal letters, including from businesses that failed. Her file needs coverage, trend, and concentration.","task":"Rewrite the opening with the three numbers a credit file actually uses.","tips":["Debt service coverage is the first number she checks — lead with it.","Show the trend: this year against last, same measure.","Name your client concentration before she asks — hiding it reads worse."],"focus":["precision","audience"],"placeholder":"Cash flow covered debt service 2.4 times this year, up from 2.1 — and our largest client is now 14% of revenue, down from 23%."},
    {"id":"precision-svc-senior-20","level":"senior","profession":"service","title":"'Below market' with a survey","scenario":"You're proposing a wage increase for line staff and your memo says pay has 'fallen below market'. The owner asks: which market, by how much, says who? The regional wage survey came out last month.","task":"Rewrite the claim with your rate, the market rate, and the source.","tips":["Name the gap in dollars per hour — that's what he'll approve or not.","Cite the survey and its date; 'below market' with a source is a fact.","Add the cost of the fix so the memo lands on a decision, not a mood."],"focus":["precision","impact"],"placeholder":"We start line staff at $17.50; the regional hospitality survey (March) puts the median at $19.25. Closing the gap costs $67k a year across the district."},
    {"id":"precision-svc-senior-21","level":"senior","profession":"service","title":"The energy bill, decomposed","scenario":"Your P&L narrative says utilities 'went crazy this quarter'. Head office will want to know: usage or rates? Old equipment or price inflation? The answer decides whether they fund new compressors or just reforecast. The bills can tell you.","task":"Write 2 sentences separating how much of the increase is rate and how much is usage.","tips":["Decompose: same usage at new rates versus new usage at old rates.","The split points at the fix — negotiation versus equipment.","'Went crazy' assigns no cause; a decomposition assigns a next step."],"focus":["precision","structure"],"placeholder":"Utilities rose $4,100 this quarter: about $2,900 is the new rate schedule, and $1,200 is real usage growth — almost all of it the aging walk-ins at two sites."},
    {"id":"precision-svc-senior-22","level":"senior","profession":"service","title":"The mystery-shop trend, not anecdotes","scenario":"You believe service at Bayview has genuinely improved since the new floor manager started, and your evidence in the draft is two nice guest comments. The ops director will weigh anecdotes at exactly zero. Three mystery-shop cycles say the same thing with numbers.","task":"Rewrite the claim using the shop-score trend instead of the anecdotes.","tips":["Three data points make a trend; two quotes make a coincidence.","Give the scores in sequence with dates.","Keep one quote if you like — as color, after the numbers."],"focus":["precision","clarity"],"placeholder":"Bayview's mystery-shop scores have climbed three cycles straight — 71 in January, 79 in March, 88 in May — the first back-to-back gains in two years."},
    {"id":"precision-svc-senior-23","level":"senior","profession":"service","title":"Counting the parking complaints","scenario":"Your case for negotiating extra parking spots with the landlord rests on the line 'everyone complains about parking'. If it's true, the reviews and comment cards can prove it; if it's not, better to find out before you spend leverage on it.","task":"Restate the claim with a real count and its base.","tips":["'Everyone' is a number between 3 and 3,000 — go count.","Give the share, not just the count: 31 of 400 reviews is an argument.","If the count is small, that's worth knowing too — precision cuts both ways."],"focus":["precision","clarity"],"placeholder":"Parking appears in 31 of our last 400 reviews — 8% — and in 19 of them it's the stated reason for not returning."},
    {"id":"precision-svc-senior-24","level":"senior","profession":"service","title":"So what for the rating slide","scenario":"Your report notes the flagship's rating slid from 4.6 to 4.2 over six months and moves on. The owner shrugs — it's still above 4. You know what a rating slide does to bookings; the report doesn't say it.","task":"Add the 'so what': translate the 0.4-point slide into business impact.","tips":["Connect the rating to the thing it drives: direct bookings, walk-ins, ranking.","Estimate honestly and label the estimate.","A stated consequence turns a shrug into a decision."],"focus":["precision","impact"],"placeholder":"The slide from 4.6 to 4.2 dropped us from 2nd to 9th in local search — direct bookings are down 12% over the same period, worth roughly $7k a month."},
    {"id":"precision-svc-senior-25","level":"senior","profession":"service","title":"The catering 'opportunity', sized","scenario":"You want the owner to fund a dedicated catering coordinator, and your pitch calls corporate catering 'a big opportunity for us'. Big is not a number. Your inquiry log, close rate, and average order can size it.","task":"Size the opportunity in 2-3 sentences: pipeline, conversion, and what the hire changes.","tips":["Inquiries times close rate times average order — that's the size.","State today's conversion and what a coordinator lifts it to, with your basis.","An opportunity with a size and a cost is a proposal; without them it's a wish."],"focus":["precision","impact"],"placeholder":"We logged 140 catering inquiries last year and closed 30 at a $1,900 average — $57k. We lose most of the rest to slow response; a coordinator who lifts conversion to 40% adds roughly $50k."}
  ],
  "executive-presence": [
    {"id":"presence-svc-senior-01","level":"senior","profession":"service","title":"Own the lease call","scenario":"Your renew-or-relocate memo for the flagship salon lays out both options with costs and risks, then ends: 'Happy to discuss whichever direction you prefer.' The owner pays you to have a view. A menu without a recommendation is analysis without a spine.","task":"Rewrite the close to state your recommendation and stand behind it.","tips":["Name your pick in the first sentence of the close.","Give the deciding reason, not a re-tour of the analysis.","Invite disagreement after the recommendation, not instead of it."],"focus":["impact","clarity"],"placeholder":"My recommendation is to renew — the 15% increase costs less over three years than the $60k fit-out plus two months of disrupted trade."},
    {"id":"presence-svc-senior-02","level":"senior","profession":"service","title":"Signposting the owner meeting","scenario":"Your monthly hour with the owner wanders — he interrupts, you loop back, decisions slip to the parking lot. The content is fine; the meeting has no audible shape. Signposts would let him relax and follow.","task":"Write the three signpost sentences: the opening map, one transition, and the close.","tips":["Open with the shape: 'three things — results, one problem, one decision.'","Mark the transition so he knows the problem section is ending.","The close names what you need from him before he stands up."],"focus":["structure","impact"],"placeholder":"Three things this month: the numbers, the Bayview problem, and one decision I need from you before you leave."},
    {"id":"presence-svc-senior-03","level":"senior","profession":"service","title":"Fact versus judgment on the walkout","scenario":"Your write-up of the Saturday walkout blends what happened with what you think it means — the reader can't tell your camera from your opinion. The owner disputes one interpretation and suddenly your facts are in question too.","task":"Write two labeled lines: one stating only facts, one stating your judgment.","tips":["Facts are what the schedule and the footage show; judgment is what you conclude.","Blending them lets a reader dodge your judgment by attacking your facts.","Separated, both get harder to argue with."],"focus":["clarity","structure"],"placeholder":"Fact: three servers left at 7:40 p.m. after a schedule dispute; the GM covered the floor and no service stopped. Judgment: this was a management failure weeks in the making, and the fix is scheduling practice, not discipline."},
    {"id":"presence-svc-senior-04","level":"senior","profession":"service","title":"The recommendation against the first location","scenario":"The owner's original restaurant — the one he opened thirty years ago — now loses money every month, and every analysis you run says close it. Your draft memo circles the conclusion with hints and hedges. Presence means saying the hard thing plainly.","task":"Write the recommendation in one clear sentence, owning the unpopular call.","tips":["Hedging a hard call reads as knowing and not saying — worse than either.","State it as a recommendation, not a question or a 'we might consider'.","Honor what the site was in the next sentence, not instead of the first one."],"focus":["impact","clarity"],"placeholder":"I recommend we close the original King Street location when the lease ends — it has lost money for nineteen straight months and the trend is worsening."},
    {"id":"presence-svc-senior-05","level":"senior","profession":"service","title":"Standing behind the budget","scenario":"You present next year's district budget and immediately add, 'but obviously these numbers could go anywhere, who knows with this economy.' The owner now trusts neither the budget nor you. The risk is real; disowning the number isn't the way to show it.","task":"Restate the budget with conviction, bounding the risk without collapsing the number.","tips":["Own the number, then name the one swing factor — don't dissolve into fog.","'I'm confident in the plan; the variable is summer traffic' shows command.","If you undercut your own estimate, everyone else will too."],"focus":["impact","precision"],"placeholder":"I stand behind the $1.2M plan. The one factor that could move it more than 3% is summer tourist traffic, and here's how we'd respond."},
    {"id":"presence-svc-senior-06","level":"senior","profession":"service","title":"Open the meeting like you called it","scenario":"You open the monthly managers' meeting by asking if everyone can hear, apologizing for the timing, and asking what people want to cover. Within minutes the loudest GM has the agenda. You called this meeting; the room should feel that.","task":"Write an opening 2-3 sentences that assert what the meeting is about and where it's going.","tips":["Frame the meeting before anyone else can.","Say the one thing that matters this month and the decision on the table.","Warmth is fine; abdication dressed as politeness is not."],"focus":["impact","structure"]},
    {"id":"presence-svc-senior-07","level":"senior","profession":"service","title":"First words to the acquired teams","scenario":"You've just taken over two sites from the retiring operator, and tomorrow you meet their staff — people who've heard nothing but rumors for a month. Over-promising will cost you in six months; visible nerves will cost you tomorrow. They need calm certainty about what you actually know.","task":"Write the first 3-4 sentences of your address: who you are, what changes, what you'll promise and won't.","tips":["Say plainly what is decided and what isn't — certainty about the boundary is still certainty.","Make one small promise you can keep this week; skip the grand ones.","Steady beats inspiring on day one."],"focus":["audience","impact"]},
    {"id":"presence-svc-senior-08","level":"senior","profession":"service","title":"De-hedging the deferral ask","scenario":"Your remodel-deferral pitch to the franchise consultant is wrapped in 'we were hoping maybe', 'if at all possible', and 'I completely understand if not'. You've pre-surrendered. The ask is reasonable; the language keeps apologizing for it.","task":"Rewrite the ask in 2 sentences with at most one qualifier.","tips":["'I'm requesting' carries respect and confidence at once.","Pre-emptive surrender invites the no it fears.","Keep one honest acknowledgment of their constraint — that's diplomacy, not hedging."],"focus":["concision","impact"],"placeholder":"I'm requesting a six-month deferral on the Elm Street remodel. The brand gets a stronger remodel out of it — funded from a full high season rather than borrowed cash."},
    {"id":"presence-svc-senior-09","level":"senior","profession":"service","title":"'We could maybe consider' the increase","scenario":"Menu costs are up 9% and your memo to the owner reads: 'We could maybe consider possibly looking at some kind of price adjustment at some point.' You've run these restaurants for a decade. Four hedges are doing the work one recommendation should.","task":"Rewrite as a direct recommendation with the number and the date.","tips":["'I recommend' plus a number plus a date — that's the whole sentence.","Your expertise is the product; hedging gives it away.","One qualifier maximum, and make it a real one."],"focus":["impact","concision"],"placeholder":"I recommend a 4% menu increase on March 1 — it covers the cost rise with margin intact, and it's below what both competitors just took."},
    {"id":"presence-svc-senior-10","level":"senior","profession":"service","title":"The memo that sounds decided","scenario":"Your policy memo reads: 'It has been determined that consideration will be given to the implementation of revised closing procedures.' Nobody decided anything in that sentence. You decided it, yesterday, at your desk.","task":"Rewrite the sentence with a decider, a decision, and a date.","tips":["Passive voice launders the decision out of the sentence — put yourself back in.","'I've decided' or 'We're changing' names an owner readers can trust or question.","A decided voice gets compliance; a determined-that voice gets ignored."],"focus":["clarity","impact"],"placeholder":"I've changed the closing procedures, effective Monday. Here's what's different and why."},
    {"id":"presence-svc-senior-11","level":"senior","profession":"service","title":"Calibrated confidence on a mixed quarter","scenario":"The quarter was genuinely mixed: revenue up 5%, but the flagship's rating slid and a key GM resigned. Your draft to the owner spins it sunny; your gut wants to spin it grim. Presence is reporting both truths at their actual size.","task":"Write a 3-sentence summary that holds the good and bad news in honest proportion.","tips":["Neither trumpets nor sackcloth — state each fact at its real weight.","Sequence deliberately: headline, counterweight, your read.","'My read is' marks the judgment honestly and owns it."],"focus":["precision","impact"],"placeholder":"Revenue grew 5% and five of six sites hit plan — a solid quarter on the numbers. Two things temper it: the flagship's rating slide and losing Marcus."},
    {"id":"presence-svc-senior-12","level":"senior","profession":"service","title":"The delivery position, stated","scenario":"On the franchisor call about your proposed delivery pilot, your instinct is to present the data and let the brand team conclude. They won't — they'll defer it. You own the P&L; the call needs your position stated, then defended.","task":"Write the spoken 2-3 sentences that state your position and invite challenge on your terms.","tips":["Position first: 'I want to run this pilot, and here's the bounded version.'","Data supports a stated position; it doesn't substitute for one.","'Tell me what would make you comfortable' invites challenge without surrendering the frame."],"focus":["impact","structure"]},
    {"id":"presence-svc-senior-13","level":"senior","profession":"service","title":"'What do you think?' deserves a position","scenario":"The owner forwards you a broker listing — the failing bistro two doors from your flagship is for sale — with one line: 'What do you think?' Your drafted reply lists pros and cons and asks what he thinks. He asked first.","task":"Write a reply that gives your actual view with a confidence level, in 2-3 sentences.","tips":["Answer the question asked: a view, not a survey of considerations.","Calibrate honestly: 'strong yes', 'lean no', 'need one fact to decide'.","Name the one thing that would change your mind — that's confidence, not hedging."],"focus":["clarity","impact"],"placeholder":"Lean no. The location fails for reasons a new owner inherits — no parking, wrong side of the foot traffic — and our capital works harder in the patio build."},
    {"id":"presence-svc-senior-14","level":"senior","profession":"service","title":"Fact and judgment in the audit response","scenario":"Your written response to the failed brand audit argues with the findings in one breath and accepts them in the next. The franchisor can't tell what you concede and what you contest. Separate the record from your read of it.","task":"Write the response's opening: one sentence of accepted fact, one of contested fact, one of judgment.","tips":["Concede what the evidence shows, precisely and without wriggle.","Contest only what you can evidence — and label it as contested.","Your judgment paragraph is where the plan lives, not the excuses."],"focus":["precision","structure"],"placeholder":"The temperature-log gaps are accurate and I accept them. The storage finding reflects a delivery in progress, and I'm contesting it with timestamped photos."},
    {"id":"presence-svc-senior-15","level":"senior","profession":"service","title":"The steady press statement","scenario":"The local paper is running the lobby-fall story tomorrow and has asked for comment. Your first draft is defensive; your second is corporate fog. What survives print is three sentences of steady fact and visible care — the register matters as much as the content.","task":"Write the 2-3 sentence statement: fact, care, action — no panic, no evasion.","tips":["A statement is quoted, not read — every sentence must stand alone.","Care for the person comes before defense of the process.","Steady, plain sentences read as command; qualifiers read as guilt."],"focus":["audience","impact"],"placeholder":"Our first concern is our guest, who is recovering and whom we've been in contact with daily."},
    {"id":"presence-svc-senior-16","level":"senior","profession":"service","title":"Signposting the annual meeting speech","scenario":"You speak for fifteen minutes at the investors' annual dinner, and last year you watched them lose the thread by minute four. The content held together on paper; out loud it had no signposts. Ears need the map ahead of the terrain.","task":"Write the spoken map: the opening signpost and the two transition sentences.","tips":["'Three chapters tonight: the year, the bet we made, and next year' — that's the map.","Transitions repeat the map: 'That's the year. Now the bet.'","Spoken structure has to be twice as loud as written structure to be heard at all."],"focus":["structure","audience"]},
    {"id":"presence-svc-senior-17","level":"senior","profession":"service","title":"Owning the vendor call that failed","scenario":"The payroll provider you personally selected and championed has botched three cycles, and you're switching back. Your draft note to the owner spreads the blame across the selection committee and the vendor's sales pitch. There was no committee. It was your call.","task":"Write 2-3 sentences that own the decision, state the fix, and keep your authority intact.","tips":["'I chose them, and I was wrong' — ownership stated once, cleanly, builds more trust than it spends.","Move fast to the fix; ownership without a fix is just confession.","Note what the miss taught you — that's the part that compounds."],"focus":["clarity","impact"],"placeholder":"The payroll switch was my call and it didn't work — three cycles, three sets of errors. We're back on the old system Friday, and here's what I'm changing about how I vet vendors."},
    {"id":"presence-svc-senior-18","level":"senior","profession":"service","title":"'Here's what I need' at the bank","scenario":"In the renewal meeting you tend to narrate the business and wait for the banker to propose terms. This year you know what you need: the line at $100k, the covenant test moved to quarterly, rate held. Presence is asking for it in one breath.","task":"Write the spoken ask: what you need, in specific terms, in 2 sentences.","tips":["Name all three terms in one pass — a complete ask reads as prepared.","Anchor first; negotiating from your own number beats reacting to theirs.","You can justify after asking. Asking after justifying sounds like hoping."],"focus":["clarity","concision"],"placeholder":"Here's what I'm asking for: the line at $100k, quarterly covenant testing instead of monthly, and the rate held at prime plus one."},
    {"id":"presence-svc-senior-19","level":"senior","profession":"service","title":"Pushing back on the target","scenario":"Head office set your district's growth target at 9% — built, as far as you can tell, on a spreadsheet that ignores the roadwork year at your two best sites. Silent compliance sets you up to fail; complaint reads as weakness. The move is a respectful, evidenced counter.","task":"Write the 2-3 sentence pushback: acknowledge, counter with your number, and give the basis.","tips":["Accept the intent before contesting the number.","Counter with a specific alternative — 6% — not just 'too high'.","Your evidence is the roadwork math; presence is presenting it without apology."],"focus":["impact","precision"],"placeholder":"I'm signing up for growth, but 9% ignores a known fact: the roadwork takes our two biggest sites offline-adjacent for five months. I'll commit to 6%, and here's the build."},
    {"id":"presence-svc-senior-20","level":"senior","profession":"service","title":"The recommendation survives the mood","scenario":"You've scheduled ten minutes with the owner to recommend the Northgate closure — and he arrives furious about an unrelated insurance bill. Your instinct is to shelve the recommendation for a better day. There is no better day, and the lease clock is running.","task":"Write the 2-3 sentences that acknowledge the moment and still deliver the recommendation intact.","tips":["Name the moment briefly — pretending he isn't angry costs credibility.","Then deliver the recommendation at full strength; a softened version now is a different recommendation.","The deadline is your ally: it explains why this can't wait for a sunnier mood."],"focus":["audience","impact"]},
    {"id":"presence-svc-senior-21","level":"senior","profession":"service","title":"Recruiting the star GM","scenario":"You're across the table from the best GM in the city, currently employed and not looking. Your pitch draft lists benefits and 'growth opportunities'. She will join a leader with a plan, not a package — the pitch has to sound like someone worth working for.","task":"Write the 3-sentence spoken pitch: your plan, her part in it, and the honest hard part.","tips":["Lead with where the group is going, in numbers she can verify.","Give her a real problem to own, not a title.","Naming the hard part signals you'll tell her the truth as an employee too."],"focus":["audience","impact"],"placeholder":"We're taking the group from six sites to ten in three years, and I need someone to run the flagship like they own it."},
    {"id":"presence-svc-senior-22","level":"senior","profession":"service","title":"Three insurance options, one recommendation","scenario":"Your broker sent three coverage structures and you've forwarded the comparison to the owner with the options laid out neutrally. He'll either pick on price or send it back asking what you think. Save the round trip.","task":"Rewrite the cover note: your recommendation first, then the one-line case, then the options as backup.","tips":["The recommendation is the note; the comparison is the attachment.","Say what you optimized for — that's the judgment he's paying for.","Neutral forwarding is clerical work; a recommendation is management."],"focus":["structure","clarity"],"placeholder":"I recommend option B — slightly higher premium, but it's the only one that covers business interruption, which is our actual risk after this year."},
    {"id":"presence-svc-senior-23","level":"senior","profession":"service","title":"Killing 'we'll see'","scenario":"Your managers have asked three times whether holiday hours are changing this year, and three times you've said 'we'll see, still working through it'. Each 'we'll see' spends authority. You don't have the answer yet — but you can commit to when you will.","task":"Write the message that replaces 'we'll see' with a committed decision date and what feeds it.","tips":["If you can't commit to the answer, commit to the date of the answer.","Name what you're waiting on — it turns delay into process.","Then keep the date. That's the whole trick of being believed next time."],"focus":["clarity","concision"],"placeholder":"Holiday hours decision comes October 15, once September's traffic numbers are in. You'll have six weeks to schedule around it."},
    {"id":"presence-svc-senior-24","level":"senior","profession":"service","title":"The wage question at the town hall","scenario":"At the all-staff meeting, a cook stands up and asks when wages are going up. Two hundred people are watching how you answer, and the honest answer is: partially, for some roles, in the spring. A politician's non-answer will cost you the room.","task":"Write the spoken 3-sentence answer: what's decided, what isn't, and when they'll know the rest.","tips":["Answer with what is actually decided — specifics defeat cynicism.","Draw the boundary honestly: what's still open and why.","Commit to the date they'll hear more, and be the one who tells them."],"focus":["audience","clarity"]},
    {"id":"presence-svc-senior-25","level":"senior","profession":"service","title":"The verdict sentence for the year","scenario":"Your annual report to the owner opens with two pages of narrative before anything resembling a conclusion. He'll ask someone at the golf course how your year went, and he'll repeat whatever your first sentence gave him. Right now it gives him weather.","task":"Write the one opening sentence that carries your verdict on the year — claim, number, and stance.","tips":["The sentence he'd repeat to a friend: that's the standard.","It must contain a judgment word (strong, mixed, turnaround) and a number.","Everything after exists to prove this sentence — so write it first."],"focus":["impact","concision"],"placeholder":"This was the group's strongest year since 2019 — 7% growth, every site profitable — with one problem we haven't cracked: turnover."}
  ],
  "answering-under-pressure": [
    {"id":"pressure-svc-senior-01","level":"senior","profession":"service","title":"'Are we going to make payroll?'","scenario":"Cash has been tight since the roadwork started, and the owner calls with one question: are we going to make payroll this month? You want to walk him through the receivables timeline and the line of credit. That's the support, not the answer.","task":"Answer the question in the first word, then support it in 2 sentences.","tips":["Yes or no leads; the mechanics follow.","Give the two facts that make the yes solid: cash on hand, the draw available.","A direct answer to a scary question is the most calming thing you can say."],"focus":["clarity","impact"],"placeholder":"Yes. We have $41k in the account against a $38k run, and $25k undrawn on the line if a receivable slips."},
    {"id":"pressure-svc-senior-02","level":"senior","profession":"service","title":"The banker's what-if","scenario":"Mid-renewal, your banker asks: 'What happens to repayment if the Harbourfront contract walks?' It's your biggest contract and she knows it. You want to say it won't walk. That's not the question she asked.","task":"Write a 2-3 sentence answer that takes the what-if seriously and answers it with numbers.","tips":["Answer the hypothetical as posed — dodging it confirms her worry.","Show the math without the client: coverage still above 1.5, and the cost base you'd cut.","Then, and only then, note the contract's 18-month term and renewal history."],"focus":["precision","clarity"],"placeholder":"If Harbourfront left tomorrow, coverage drops from 2.4 to about 1.6 — still above covenant — and $9k a month of direct staffing cost leaves with it."},
    {"id":"pressure-svc-senior-03","level":"senior","profession":"service","title":"The reporter on line two","scenario":"A local reporter calls about the viral billing-dispute video: 'Do you have a comment?' Everything you say can be quoted; saying nothing becomes 'declined to comment' under the video. You need three sentences that are true, calm, and complete.","task":"Write the phone statement: what happened, what you did, and where it stands.","tips":["Speak in complete, quotable sentences — fragments get completed for you.","Facts and the remedy; no speculation about the customer's motives.","Say what you won't discuss (personnel) once, without irritation."],"focus":["audience","clarity"],"placeholder":"We reviewed the incident the day it was posted, refunded the client in full, and changed how we explain charges before service."},
    {"id":"pressure-svc-senior-04","level":"senior","profession":"service","title":"'Why did Elm Street fail?'","scenario":"The franchisor's field consultant asks you directly why Elm Street failed its audit. You have a paragraph of context queued up — the manager transition, the delivery that morning, the auditor's mood. He's heard every version of that paragraph from every franchisee.","task":"Write the 2-sentence answer that owns the cause before any context.","tips":["Lead with the real cause, owned: supervision lapsed during the manager transition.","One sentence of context is calibration; three is excuse.","The fastest way to be trusted with the fix is to be straight about the cause."],"focus":["clarity","impact"],"placeholder":"Elm Street failed because supervision lapsed during the GM handover — the logs stopped getting checked, and that's on me."},
    {"id":"pressure-svc-senior-05","level":"senior","profession":"service","title":"The honest 'I don't know' on the illness report","scenario":"Two guests reported illness after Saturday dinner and the owner asks point-blank: was it us? You genuinely don't know — the health unit hasn't traced it, and the same weekend had a stomach bug going around the schools. Guessing either way is dangerous.","task":"Write a 2-3 sentence answer that is honest about the uncertainty and gives a path to the answer.","tips":["Separate what you know (two reports, dates, dishes) from what you don't (causation).","Name what you've already done — records pulled, health unit engaged.","Commit to when you'll know more. Uncertainty with a date is an answer."],"focus":["clarity","precision"],"placeholder":"I don't know yet, and I won't guess. Two reports, both Saturday dinner; I've pulled the records, held the supplier lot, and the health unit will have preliminary findings Thursday."},
    {"id":"pressure-svc-senior-06","level":"senior","profession":"service","title":"'So profits matter more than people?'","scenario":"At the town hall about the schedule changes, a longtime server asks: 'So this is about profits mattering more than us, right?' The framing is a trap — yes concedes, no sounds defensive, and two hundred coworkers are listening. Answer the real question underneath.","task":"Write the spoken 2-3 sentence response that reframes without dismissing her.","tips":["Don't accept the either/or — name the real question: does this change make your job worse?","Answer that question concretely: what changes for a server's week, honestly.","Respect the anger; it's information. Condescension loses the room permanently."],"focus":["audience","impact"]},
    {"id":"pressure-svc-senior-07","level":"senior","profession":"service","title":"'You said that last quarter'","scenario":"You tell the owner Bayview's turnaround is taking hold, and he cuts in: 'You said exactly that last quarter.' He's right — you did. The answer that saves you is not a better adjective; it's the specific difference between then and now.","task":"Write a 2-3 sentence response that concedes the history and names what's different, with evidence.","tips":["Concede first, fully: 'I did, and it slipped.' The concession buys the hearing.","Then the difference in facts, not confidence: new GM in seat six weeks, three metrics moving.","Offer the checkpoint: 'judge me on the March numbers.' A date makes it accountable."],"focus":["precision","impact"],"placeholder":"You're right, I did — and it slipped because I was betting on a manager who quit. The difference now: Dana's been in the seat six weeks and covers, labor, and reviews have all moved."},
    {"id":"pressure-svc-senior-08","level":"senior","profession":"service","title":"'Will the build stay on budget?'","scenario":"The owner asks whether the Lakeside build-out will land on its $230k budget. Truthfully: probably, but the electrical quote came in $12k heavy and you haven't absorbed it yet. The tempting answer is 'yes'. The right answer carries the risk.","task":"Write the 2-sentence answer: the honest verdict with the one named risk.","tips":["'Yes, with one exception' is a stronger answer than a clean yes that breaks later.","Size the risk: $12k on $230k, and what you're doing about it.","The question behind the question is 'will I be surprised?' — answer that one."],"focus":["clarity","precision"],"placeholder":"On budget with one open risk: electrical quoted $12k over, and I'll know by Friday whether value-engineering the panel closes it."},
    {"id":"pressure-svc-senior-09","level":"senior","profession":"service","title":"The landlord's comparison","scenario":"You ask for rent relief during the roadwork and the landlord fires back: 'The cafe next door pays full rent. Why should you be different?' It's a fair question with a real answer — your exposure isn't theirs — and a flustered answer wastes it.","task":"Write the 2-3 sentence response that engages the comparison with facts instead of protest.","tips":["Take the premise seriously — 'good question' beats visible irritation.","Differentiate with facts: your entrance faces the trench; theirs faces the side street.","Return to your evidence: the 38% transaction drop is yours, whatever the cafe's is."],"focus":["precision","impact"],"placeholder":"Fair question — the difference is geography. Our only entrance faces the excavation; their doors open on Elm. My transactions are down 38%; I'd encourage you to ask what theirs are."},
    {"id":"pressure-svc-senior-10","level":"senior","profession":"service","title":"'Would you put your own money in?'","scenario":"Pitching the two investors on funding site five, one of them leans back and asks: 'Would you put your own money into this one?' There is exactly one honest answer, and it happens to be yes — you're planning to. But the answer needs to land as fact, not performance.","task":"Write the 2-sentence answer with the specific commitment that makes it credible.","tips":["Answer in one word, then make it concrete: the amount and the terms.","Same terms as theirs is the sentence that closes the question.","If the honest answer were no, the pitch has a bigger problem than this drill."],"focus":["clarity","impact"],"placeholder":"Yes — I'm putting in $75k of my own on the same terms you're being offered, and I'll show you the commitment letter."},
    {"id":"pressure-svc-senior-11","level":"senior","profession":"service","title":"The inspector's pointed question","scenario":"Mid-inspection, the health inspector points at the walk-in log and asks: 'How long has this cooler been running warm?' The log shows three days of borderline readings that nobody escalated. She can see the log. The only workable answer is the true one.","task":"Write the answer: the fact, the failure, and the immediate action, in 2-3 sentences.","tips":["Answer the question asked: three days, per the log.","Name the failure plainly — the escalation didn't happen — no cushioning.","State what happens in the next hour, not the next month. Inspectors score response."],"focus":["precision","clarity"],"placeholder":"Three days, per the log — the readings were borderline and my team failed to escalate them. The unit's being serviced this afternoon and everything in it is moving to the backup now."},
    {"id":"pressure-svc-senior-12","level":"senior","profession":"service","title":"'Why was the sign missing?'","scenario":"The insurance adjuster asks why there was no wet-floor sign at the time of the lobby fall. You don't actually know yet — the footage is ambiguous and the porter's statement is pending. Speculating on the record could cost the claim; stonewalling looks worse.","task":"Write the answer that states what's known, what's pending, and when the file completes.","tips":["Answer with the record: what the footage shows, what it doesn't.","Never guess into a claims file — 'the porter's statement will establish that' is an answer.","Give the date the complete file arrives; adjusters forgive gaps, not drift."],"focus":["precision","audience"],"placeholder":"The footage confirms the sign wasn't in place; whether it was removed or never deployed is what the porter's statement will establish — you'll have the complete file by Friday."},
    {"id":"pressure-svc-senior-13","level":"senior","profession":"service","title":"'Give me one reason to renew'","scenario":"Your biggest cleaning client opens the renewal call with: 'We've had three complaints this year. Give me one reason I shouldn't tender this contract.' He wants to see whether you flinch, deflect, or answer. You have one good answer and three defensive ones.","task":"Write the 2-3 sentence answer that meets the challenge head-on.","tips":["One reason means one — pick your strongest and commit to it.","Own the three complaints in a clause, not a paragraph.","The confident answer names what a tender would actually find: your response times against the market's."],"focus":["impact","concision"],"placeholder":"The three complaints were real and each was fixed inside 24 hours — and that's the reason: tender it, and you'll find nobody else guarantees same-day resolution at this price."},
    {"id":"pressure-svc-senior-14","level":"senior","profession":"service","title":"'How much of this is on you?'","scenario":"After the worst quarter in three years, the owner asks quietly: 'How much of this is on you?' Deflecting to the market insults him; theatrical self-blame helps nobody. The credible answer apportions honestly — your part, named precisely.","task":"Write the 2-3 sentence answer that owns your specific share without groveling or dodging.","tips":["Name your actual mistakes: held the Bayview GM too long, deferred the marketing spend.","Separate what you'd redo from what you'd decide the same way with the same facts.","Precision about your own failures is the strongest presence move there is."],"focus":["clarity","impact"]},
    {"id":"pressure-svc-senior-15","level":"senior","profession":"service","title":"'Are there going to be layoffs?'","scenario":"During the site visit, a supervisor asks you straight: 'Are there going to be layoffs?' The truth: no decision yet, back-office consolidation is being studied, and front-line roles aren't in scope. 'I can't comment' will be heard as yes.","task":"Write the answer that gives the honest boundary: what's true, what's undecided, when they'll know.","tips":["Say what is decided — front-line roles aren't being looked at — because it's most of the fear.","Name what's genuinely open without euphemism: back-office is under review.","Commit to a date and to them hearing it from you first."],"focus":["audience","clarity"],"placeholder":"No decision's been made, and front-line roles aren't part of what's being looked at. Back-office consolidation is under review — you'll know by month end, and you'll hear it from me."},
    {"id":"pressure-svc-senior-16","level":"senior","profession":"service","title":"The doorstep question","scenario":"Leaving the hotel after the incident review, you find a reporter at the staff entrance: 'Guests are saying management ignored complaints about that floor. Did you?' You have a statement approved for tonight; this is not the place to improvise a new one.","task":"Write the 2-sentence doorstep response: one true thing, and the bridge to the statement.","tips":["Never repeat the accusation's words — answer without echoing 'ignored'.","One factual sentence you'd stand behind in print, then the bridge: full statement at six.","Walking away silent is footage; a calm bridge is a non-story."],"focus":["audience","concision"],"placeholder":"Guest safety is exactly what our review covered, and we're publishing what we found tonight at six — I'll make sure you get it first."},
    {"id":"pressure-svc-senior-17","level":"senior","profession":"service","title":"Three questions at once","scenario":"The regional VP fires a burst on the call: 'Where's Bayview's turnaround, what's your Q4 labor number, and did the Lakeside permit clear?' Answering in the order asked buries your best news and drags the call through the swamp first.","task":"Write the spoken answer that signposts and sequences all three deliberately.","tips":["Signpost first: 'Three answers — quick ones first.'","Clear the two fast facts, then give the complex one room.","Sequencing under fire reads as command; answering in received order reads as reacting."],"focus":["structure","clarity"],"placeholder":"Three answers, quick ones first: the permit cleared Tuesday, Q4 labor lands at 30.1% — and Bayview needs a fuller minute, because the news is mixed."},
    {"id":"pressure-svc-senior-18","level":"senior","profession":"service","title":"'Why is District 4 cheaper?'","scenario":"Head office benchmarks you against District 4 and asks why your cost per cover runs 6% higher. You know the real answer — their sites are newer, bigger, and suburban — but 'it's not comparable' sounds like every manager who ever missed a number.","task":"Write the answer that engages the comparison with facts and concedes what's real.","tips":["Decompose the 6%: how much is structural (rent, site size) and how much is yours.","Concede your controllable share and name its fix — that's what buys the structural argument.","'Here's the like-for-like number' beats 'you can't compare us'."],"focus":["precision","structure"],"placeholder":"About 4 of the 6 points are structural — downtown rents and half-size kitchens. The other 2 are mine: waste at two sites, and here's the fix already running."},
    {"id":"pressure-svc-senior-19","level":"senior","profession":"service","title":"The question you can't answer","scenario":"At the managers' meeting, someone asks why the Downtown GM suddenly left. It was a termination with a signed agreement, and you legally can't discuss it. 'No comment' breeds a week of rumors; a fake cover story breeds worse when it leaks.","task":"Write the answer that declines specifics without stonewalling the room.","tips":["Name the boundary honestly: personnel matters stay private — as yours would.","Answer the question under the question: the site is stable, here's interim coverage.","Kill the rumor's oxygen with what you CAN say, said fully."],"focus":["audience","clarity"],"placeholder":"I can't discuss why anyone leaves — you'd want the same privacy. What I can tell you: Downtown is covered, Priya is interim GM as of today, and the role posts Friday."},
    {"id":"pressure-svc-senior-20","level":"senior","profession":"service","title":"The buyer's due-diligence jab","scenario":"You're selling the group, and the buyer's accountant slides a page across: 'Revenue's down at two of six sites. What aren't you telling us?' The insinuation stings, but the facts are ordinary — roadwork at one, a planned repositioning at the other. Indignation reads as concealment.","task":"Write the 2-3 sentence answer: direct, factual, and unshaken by the framing.","tips":["Ignore the insinuation entirely; answer the number.","One cause per site, each checkable against documents they already hold.","Point them to where it's disclosed — 'page 12 of the package' ends the theater."],"focus":["precision","impact"],"placeholder":"Both are disclosed on page 12. Central's dip is the city roadwork — permits attached — and Kingsway's is the repositioning we chose, which you can see recovering from March."},
    {"id":"pressure-svc-senior-21","level":"senior","profession":"service","title":"'When exactly?'","scenario":"The elevator has been out for four days and a corporate group's event lands Saturday. The client's coordinator asks: 'When exactly is it fixed?' The contractor says Thursday, 'barring parts issues'. Passing along that fog will lose the booking.","task":"Write the answer that commits to a date with an honest bound and a backup.","tips":["Give the date and your confidence: Thursday, high confidence, confirmed parts.","Then the backstop: what happens Saturday if Thursday slips — porters, freight elevator, comps.","A date plus a contingency answers 'when' AND the question behind it: 'am I safe booking you?'"],"focus":["precision","clarity"],"placeholder":"Thursday — the parts arrived this morning and install is booked. If anything slips, your event still runs: dedicated porters and the service elevator, and I'll personally confirm with you Friday noon."},
    {"id":"pressure-svc-senior-22","level":"senior","profession":"service","title":"'What's your worst mistake?'","scenario":"The franchise prospect touring your flagship asks: 'What's the worst mistake you've made in this business?' A dodge ('I wish I'd started sooner!') tells him you'll spin him forever. A real answer, told straight, is the most persuasive thing he'll hear all day.","task":"Write the 3-sentence answer: the real mistake, its cost, and what changed.","tips":["Pick a real one with a dollar figure — specificity is what makes honesty legible.","No redemption arc padding; mistake, cost, lesson, done.","The meta-message is the message: this person will tell me the truth."],"focus":["clarity","audience"]},
    {"id":"pressure-svc-senior-23","level":"senior","profession":"service","title":"The catering client fights the increase","scenario":"Your largest catering client calls about the 6% price increase: 'Waive it or we go to tender.' They're 15% of revenue and they know it. Caving invisibly reprices every contract you have; a flat no might lose the account. Hold the position and reframe the value.","task":"Write the 2-3 sentence response that holds the increase while giving them a real path.","tips":["Hold the number calmly — the increase has a cost basis, name it.","Reframe what tender actually finds: your delivery record priced against the market.","Offer value, not discount: locked pricing for a longer term trades something real."],"focus":["impact","clarity"],"placeholder":"The 6% stands — it's the wage floor and it's hitting every bidder you'd meet at tender. What I can do is lock this price for 24 months, which nobody bidding fresh will offer you."},
    {"id":"pressure-svc-senior-24","level":"senior","profession":"service","title":"The assumption under attack","scenario":"Presenting the Westgate turnaround, the owner attacks your core assumption: 'You're assuming foot traffic comes back. Why would it?' If the assumption dies, the plan dies. You have real evidence — the transit station opening — but also a real bound on it.","task":"Write the answer that defends the assumption with evidence and shows the plan's floor if it's wrong.","tips":["Defend with the strongest single fact: the station opens in June, 4,000 riders a day.","Concede the bound honestly: here's the plan's math at half the projected recovery.","A plan that survives its own assumption failing is the plan that gets funded."],"focus":["precision","impact"],"placeholder":"Two reasons: the transit station opens in June — 4,000 daily riders, 200 meters away — and even at half the projected recovery, the plan still clears break-even by month ten."},
    {"id":"pressure-svc-senior-25","level":"senior","profession":"service","title":"The closure-rumor question","scenario":"A Mill Road server asks during your visit: 'Is it true this place is closing? People are saying January.' The truth: closure is one of three options under review, no decision until December. Whatever you answer will be repeated verbatim in the group chat within the hour.","task":"Write the answer built to survive being repeated word for word.","tips":["Assume the group chat: every sentence must be safe and accurate quoted alone.","Don't deny what might become true; don't confirm what isn't decided.","The honest shape: what's being reviewed, when it's decided, what happens to staff in every scenario."],"focus":["audience","clarity"],"placeholder":"No decision has been made — the site's under review with a decision in December, and if anything changes, every person here gets offered a role at our other locations. You'll hear it from me, not a rumor."}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-svc-senior-01","level":"senior","profession":"service","title":"Before and after for the renovation","scenario":"You're pitching the owner a $120k dining room renovation, and your draft is a costed spec sheet. Spec sheets get deferred. What moves a decision is the contrast: the room as guests experience it tonight, and the room a year from now.","task":"Write the 3-4 sentence before/after that makes the investment feel inevitable.","tips":["Make 'today' concrete and slightly painful — the worn banquettes, the 4.2 rating mentioning 'tired'.","Make 'after' measurable, not magical: covers, check average, the rating trajectory.","The gap between the two pictures is your case; let him feel it before he prices it."],"focus":["impact","structure"]},
    {"id":"narrative-svc-senior-02","level":"senior","profession":"service","title":"The cost of doing nothing on turnover","scenario":"Your wage proposal keeps getting deferred because the status quo feels free. It isn't — 64% turnover has a price the owner pays every month without seeing it on any line. Make inaction the expensive option.","task":"Write 2-3 sentences that price the status quo in dollars and guest experience.","tips":["Doing nothing costs $61k a year in replacement — say it as a bill he's already paying.","Add the invisible cost: every new server's first month is your worst service.","The frame flips the decision: he's not spending money, he's choosing which bill to pay."],"focus":["impact","precision"],"placeholder":"We're already paying for the raise — $61k a year in replacement costs, plus every table served by someone in their first month."},
    {"id":"narrative-svc-senior-03","level":"senior","profession":"service","title":"Pre-empting 'they'll just leave anyway'","scenario":"You're pitching the supervisor-training program, and you know exactly what the owner will say: 'We'll train them and they'll leave for the hotel across town.' If he says it first, you're defending. If you say it first, you're thorough.","task":"Write the 2-3 sentences that raise his strongest objection and answer it before he can.","tips":["Name it in his words — 'you're going to ask what happens when they leave.'","Answer with the sharper question: what happens if we don't train them and they stay?","Add the retention data: trained supervisors leave less, not more. Pre-emption plus evidence ends the argument."],"focus":["impact","structure"],"placeholder":"You're going to ask: what if we train them and they leave? The costlier version is the one we're living — we don't train them, and they stay."},
    {"id":"narrative-svc-senior-04","level":"senior","profession":"service","title":"The POS change story","scenario":"The new POS goes live in three weeks, and your announcement draft is a feature list and a training schedule. Your staff lived through the last system change — the one that ate a week of tips. They don't need features; they need a story with them in it.","task":"Write the 3-4 sentence change narrative: why, what it means for them, and where it goes.","tips":["Start with a why they believe: the old system crashes every Friday rush — they know, they reboot it.","Their stake, concretely: tips post nightly instead of weekly.","Name the last rollout's pain honestly and what's different this time — trust is built at that sentence."],"focus":["audience","impact"]},
    {"id":"narrative-svc-senior-05","level":"senior","profession":"service","title":"Selling the maintenance contract","scenario":"You want the owner to fund preventive maintenance contracts across all sites — $14k a year to prevent failures that haven't happened. Prevention is the hardest sell in business, unless you make the invisible risk visible. You happen to have last month's $15k freezer disaster to work with.","task":"Write the 3-4 sentence pitch that makes the unfelt risk concrete.","tips":["Anchor on the near-disaster they remember: the freezer, the 2 a.m. calls, the lost stock.","Do the math out loud: one prevented failure pays for the whole program.","Frame it as insurance with a receipt — a quarterly report of what got caught early."],"focus":["impact","structure"],"placeholder":"Last month's freezer failure cost $15k and a weekend — one failure. The contract that would have caught it costs $14k a year across all six sites."},
    {"id":"narrative-svc-senior-06","level":"senior","profession":"service","title":"The Westgate arc","scenario":"You're presenting the Westgate turnaround to head office, and your slides are a tactic list: new GM, menu cut, schedule rebuild. Lists are forgettable and fundable things are memorable. The same facts, told as an arc — where it was, what turned, where it's pointed — become a story they retell.","task":"Write the 3-4 sentence turnaround narrative with a low point, a turning point, and a trajectory.","tips":["Establish the bottom honestly — five missed months, the walkout — so the recovery means something.","Name the turning point as a decision, not luck: the day you rebuilt the schedule around two shifts.","End on trajectory with a number: three months of climbing covers, break-even in sight."],"focus":["impact","structure"]},
    {"id":"narrative-svc-senior-07","level":"senior","profession":"service","title":"The founding story, deployed","scenario":"At dinner with a serious franchise prospect, he asks how you got started. You have a real story — the single salon chair, the loan your mother co-signed, the first winter you nearly closed. Told aimlessly it's nostalgia; aimed, it's the answer to the question he hasn't asked: can I trust this system in hard months?","task":"Write the 4-sentence version of the founding story aimed at his real question.","tips":["Choose the details that carry the point: the near-failure and what the systems learned from it.","The story's job is his objection: this business survives bad winters — here's the proof I lived.","Land it back on him: 'the manual you'd get is everything that winter taught us.'"],"focus":["audience","impact"]},
    {"id":"narrative-svc-senior-08","level":"senior","profession":"service","title":"From complaint data to Sunday staffing","scenario":"You have the data: 70% of complaints land on weekend dinners, wait times double after 7 p.m., and one host station sits empty. You've presented these facts twice and gotten nods, not decisions. Facts inform; the framed change is what persuades.","task":"Write the 3-sentence version that frames the data as a before/after decision.","tips":["Compress the data into one 'where we are' sentence — the Saturday 7:40 p.m. guest waiting 25 minutes.","Then 'where we could be': seated in 10, one staffing change, costed.","End on the bridge: the decision, its price, and the metric that proves it worked."],"focus":["structure","precision"],"placeholder":"Right now the 7:40 Saturday guest waits 25 minutes and tells four friends. One host and one server shift — $310 a weekend — makes that wait ten minutes."},
    {"id":"narrative-svc-senior-09","level":"senior","profession":"service","title":"Painting the vacant street","scenario":"The landlord is holding firm on the 15% increase, betting you won't leave. Your counter-case so far is your own hardship, which is not his problem. His problem — the one to make vivid — is what this street looks like with your corner dark.","task":"Write the 3-4 sentence narrative that makes his risk concrete.","tips":["Paint the specific picture: your frontage papered over, the third vacancy on his block.","Use his numbers: months of vacancy at this rate versus the increase he's chasing.","Stay warm — a threat framed as shared problem-solving keeps the relationship that gets deals done."],"focus":["audience","impact"],"placeholder":"Here's the scenario I want us both to avoid: this corner papered over in October, the third dark frontage on the block, while the space sits eight months finding a tenant at your asking rate."},
    {"id":"narrative-svc-senior-10","level":"senior","profession":"service","title":"The growth story for the bank","scenario":"Your line-increase request has the ratios, but ratios alone read as a spreadsheet asking for money. Bankers fund trajectories they understand: where the company was, what you built, why the next step needs this facility. Give the numbers a spine.","task":"Write the 4-sentence growth narrative that carries the ask.","tips":["Compress the arc: two trucks to twelve, one contract to forty, in five years.","Show the pattern that de-risks the ask: every past facility increase preceded a growth step that repaid it.","Land on the ask as the obvious next chapter, not a rescue."],"focus":["structure","precision"],"placeholder":"Five years ago this was two trucks and one office contract; today it's twelve trucks and forty contracts. Each time we've raised the facility, the growth that followed repaid it inside a year."},
    {"id":"narrative-svc-senior-11","level":"senior","profession":"service","title":"The legacy frame","scenario":"The retiring operator two towns over is choosing between your offer and a national chain's — theirs is 8% higher. Money won't win this; meaning might. He built those two sites over thirty years and staffs them with people whose weddings he's attended. Frame what each future looks like.","task":"Write the 3-4 sentence persuasion built on his real stake: what happens to what he built.","tips":["Make the two futures concrete: his name and his people under your plan, versus a rebrand and 'synergies' under theirs.","Evidence beats promise: name what you kept intact at the last site you bought.","Price the gap honestly — 'their offer is higher, and here's what the difference buys you' respects him."],"focus":["audience","impact"]},
    {"id":"narrative-svc-senior-12","level":"senior","profession":"service","title":"The price increase, told honestly","scenario":"The 4% menu increase takes effect March 1, and the table-tent copy from marketing says 'to continue delivering exceptional experiences'. Guests read that as 'we wanted more money'. The true story — wages up, suppliers up, portions and staff untouched — is more persuasive than the polished one.","task":"Write the 3-sentence guest-facing note that tells the honest story.","tips":["Name the real drivers plainly — people believe specifics and discount gloss.","Say what's not changing: portions, hours, the people who serve them.","One sentence of gratitude, zero sentences of 'exceptional experience'."],"focus":["audience","clarity"],"placeholder":"Our prices go up about 4% on March 1 — our team's wages and our suppliers' costs have both risen, and we won't cut portions or corners to hide it."},
    {"id":"narrative-svc-senior-13","level":"senior","profession":"service","title":"The 'why join us' story","scenario":"Your job postings compete with a hospital, a call center, and two warehouses paying similar money. Your draft ad lists duties and benefits like everyone else's. What you actually have is a story the others can't tell: the last three GMs all started on the floor.","task":"Write the 3-4 sentence recruiting narrative built on the promotion story.","tips":["Lead with the provable arc: dishwasher to GM in four years — name her if she'll let you.","Make the path explicit: what someone starting Monday can reach by when.","The competitors sell shifts; you're selling a trajectory. Keep every sentence on that."],"focus":["audience","impact"],"placeholder":"Maria started on our dish line four years ago; today she runs our busiest location. Every GM in this company started on the floor."},
    {"id":"narrative-svc-senior-14","level":"senior","profession":"service","title":"Disarming the brand-risk objection","scenario":"Your delivery-pilot proposal will hit the franchisor's standard objection: third-party drivers damage the brand experience. It's their strongest card and it's not baseless. The pitch that wins names the objection first, concedes its truth, and shows the pilot is built to answer it.","task":"Write the 2-3 sentences that raise the brand-risk objection and disarm it with the pilot's design.","tips":["State their objection at full strength — a weak version fools no one.","Show the design answer: sealed packaging, two sites, weekly brand-experience audits, a kill switch.","A bounded pilot with a kill switch shrinks the decision from bet to experiment."],"focus":["impact","structure"],"placeholder":"The real concern is brand experience in a driver's hands — I agree, and the pilot is built around it: two sites, tamper-sealed packaging, weekly experience audits, and we shut it down at the first sustained dip."},
    {"id":"narrative-svc-senior-15","level":"senior","profession":"service","title":"Site five, with stakes","scenario":"Your investors made money on sites three and four, but this pitch for site five is landing flat — it reads as more of the same, and 'more of the same' doesn't move money that's comfortable where it sits. The missing piece is stakes: what waiting costs.","task":"Write the 3-4 sentence pitch with a before/after and the concrete cost of waiting.","tips":["The after: the anchored corner site, the demographic data, year-two cash flow at site three's proven curve.","The stakes: this space leases to someone in 90 days — name who's circling.","Their money's alternative is 4% in a GIC; show the same dollars on your proven curve."],"focus":["impact","precision"]},
    {"id":"narrative-svc-senior-16","level":"senior","profession":"service","title":"One guest's Friday night","scenario":"Your service-standards report to the owner shows the numbers: waits up, table checks missed, rating down 0.4. He's seen these slides quarterly and nothing has moved him. Numbers describe the problem; one guest's evening makes him feel it.","task":"Write the 4-sentence walk-through of one composite guest's Friday night, built from the real data.","tips":["Every beat must be data-backed: the 25-minute wait is your actual P75, not drama.","Keep it cool and specific — melodrama discredits, precision indicts.","Land it back on the numbers: 'that evening, times 340 covers, is the 0.4 we lost.'"],"focus":["impact","audience"]},
    {"id":"narrative-svc-senior-17","level":"senior","profession":"service","title":"The standards rally","scenario":"Pre-season all-staff meeting, two hundred people, and your draft speech is the standards checklist read aloud: greet in 30 seconds, check back in two minutes. Checklists inform and evaporate. A story about why the standards exist is what walks out the door with them.","task":"Write the 4-sentence spoken opening that carries the standards inside a story.","tips":["One story, real, small: the regular who told you she picks your cafe because someone remembers her order.","Let the standards fall out of the story — the checklist becomes 'how we make that happen 400 times a night'.","End the opening on identity, not instruction: this is what we're known for."],"focus":["audience","impact"]},
    {"id":"narrative-svc-senior-18","level":"senior","profession":"service","title":"The kiosk, framed forward","scenario":"Your business partner championed the mall kiosk, and eighteen months of losses haven't moved him because closing it means he was wrong. Your last pitch relitigated the past — his defenses went up in the first sentence. Reframe: the decision isn't about the old bet; it's about what the next $30k does.","task":"Write the 3-sentence persuasion framed entirely forward.","tips":["Honor the original logic in one clause — it was a reasonable bet on the traffic data you both had.","Frame the real choice: the next 12 months of losses versus the same $30k in the patio that returns 20%.","Give him a graceful exit: 'the kiosk taught us where our margin actually lives.'"],"focus":["structure","impact"],"placeholder":"The kiosk was the right bet on the data we had — and it's answered the question. The real decision now is where the next $30k works harder: covering its losses, or building the patio."},
    {"id":"narrative-svc-senior-19","level":"senior","profession":"service","title":"Selling consolidation to your own managers","scenario":"Consolidating to one produce supplier saves $30k a year, but your GMs love their local vendors — the guy who saves the best tomatoes, the one who delivers on Sundays. A savings number from head office is exactly the story they're primed to resist. Tell it in their stakes.","task":"Write the 3-4 sentence case addressed to the GMs' actual interests.","tips":["Their stake first: the $30k funds the second grill and the kitchen aircon they've asked about for two years.","Concede what's real about the loss — Sunday delivery — and show the fix in the new contract.","Let them keep something: one local specialty line per site keeps the relationship and the tomatoes."],"focus":["audience","structure"]},
    {"id":"narrative-svc-senior-20","level":"senior","profession":"service","title":"The neighborhood association","scenario":"Your patio application faces the neighborhood association tonight, and they've killed two before it — both applicants led with business benefits. The residents' stakes are noise at 11 p.m., parking, and precedent. Your case has to live in their evening, not your revenue.","task":"Write the 3-4 sentence spoken case built on the residents' stakes.","tips":["Open with their concern, answered concretely: patio closes at 10, no amplified sound, written into the license.","Offer the enforcement they don't expect: a direct line to you, and a review at the end of one season.","A bounded, revocable yes is an easy yes — make this season a trial they control."],"focus":["audience","impact"],"placeholder":"Let me start with the 11 p.m. question, because it's the right one: the patio closes at 10, no speakers, and both are written into the license you can hold us to."},
    {"id":"narrative-svc-senior-21","level":"senior","profession":"service","title":"Closing Sundays as a change story","scenario":"The decision is made: Mill Road closes Sundays starting next month. Announced as a cut, the staff hear decline and the regulars hear the beginning of the end. Announced as a change with a destination — better Saturdays, fresher crew, the brunch launch — the same fact reads as a plan.","task":"Write the 3-sentence announcement that frames the closure as a deliberate move toward something.","tips":["The destination first: what the freed hours and dollars build.","Be honest that Sundays weren't working — a frame isn't a fib.","Give the regulars somewhere to land: Saturday brunch, extended Friday hours."],"focus":["impact","clarity"],"placeholder":"Starting next month we're putting everything into six great days instead of seven stretched ones — Sundays close, and the hours move into the new Saturday brunch."},
    {"id":"narrative-svc-senior-22","level":"senior","profession":"service","title":"The risk-improvement story for the insurer","scenario":"Your liability premium is up 22% at renewal, priced off the claim year from hell — the lobby fall and the kitchen fire. The broker says the underwriter 'sees a deteriorating risk'. The counter-story, with receipts: those two claims triggered a safety overhaul that makes you a better risk than before either happened.","task":"Write the 4-sentence narrative for the underwriter: the claims, the turn, the evidence.","tips":["Don't minimize the claims — they're on the record; own them as the turning point.","Evidence each improvement: the audit, the training hours, the incident-rate trend since.","End on the ask reframed: you're not pricing last year's operation."],"focus":["precision","structure"],"placeholder":"The two claims in 2024 are real — and they're why we're a different risk today: a third-party safety audit, 400 staff training hours, and eleven incident-free months since."},
    {"id":"narrative-svc-senior-23","level":"senior","profession":"service","title":"Winning against the cheaper bid","scenario":"The Harbourfront renewal comes down to you and a bidder 12% cheaper. Procurement's spreadsheet can't see what you know: their last building went through three account managers in a year, and a missed patrol is invisible until the night it isn't. Make the cost of failure vivid without naming the competitor.","task":"Write the 3-4 sentence differentiation narrative for the renewal meeting.","tips":["Never disparage the rival — describe the failure mode generically and let them map it.","Make the invisible visible: what a missed patrol costs in one incident versus 12% a year.","Anchor on your record with their building: response times, the flood catch last March, zero turnover on their account."],"focus":["impact","precision"]},
    {"id":"narrative-svc-senior-24","level":"senior","profession":"service","title":"The case for promoting Dana","scenario":"The owner wants to recruit a big-name GM from the city for the flagship; you want to promote Dana, who ran Riverside's turnaround. His frame is 'we need proven talent'. Your job is a narrative where Dana IS the proven talent — and the outside hire is the actual gamble.","task":"Write the 3-4 sentence persuasion that reframes which choice is the risk.","tips":["Flip the risk frame with evidence: Dana's results are in YOUR business; the star's are in someone else's.","Cost the downside of each miss: a failed outside hire costs a year and the flagship's momentum.","Give his concern its due: name what Dana lacks and how you'll cover it — a mentor, a course, your Tuesdays."],"focus":["structure","audience"],"placeholder":"The proven candidate is already on payroll: Dana's turnaround numbers happened in our kitchens, with our margins. The outside hire is the gamble — proven somewhere else is unproven here."},
    {"id":"narrative-svc-senior-25","level":"senior","profession":"service","title":"One more year for Bayview","scenario":"Head office wants Bayview on next quarter's closure list. You believe it's twelve months from viable — the transit station, the new GM, three months of improving covers — but 'I believe in this site' is sentiment, and sentiment loses to a spreadsheet. Build the bridge narrative: from here to viable, with checkpoints they control.","task":"Write the 4-sentence case: the trajectory, the catalyst, the checkpoints, and the bounded ask.","tips":["Lead with the trend, not the plea: three months of climbing covers, each better than the last.","Name the external catalyst with a date — the June station opening isn't hope, it's infrastructure.","Bound the ask with their kill switch: quarterly gates they set; miss one and you close it yourself."],"focus":["impact","structure"],"placeholder":"Bayview's covers have climbed three straight months, and the June transit opening puts 4,000 daily riders at its door. I'm asking for four quarters with gates you set — miss one, and I'll recommend the closure myself."}
  ],
  "delivering-hard-messages": [
    {"id":"hard-svc-senior-01","level":"senior","profession":"service","title":"Announcing the Northgate closure","scenario":"The decision is final: Northgate closes when the lease ends in March, and its eleven staff hear it from you tomorrow morning. Your drafted opening spends four sentences on market conditions before the word 'close' appears. They'll know from your face; the delay just adds cruelty.","task":"Write the opening 2-3 sentences that front-load the news and what it means for them.","tips":["The closure fact goes in sentence one — searching for it in a preamble is agony.","Immediately follow with their piece: every one of them offered a role at another site.","Save the market context for questions; nobody grieving a workplace wants a macro briefing."],"focus":["clarity","impact"],"placeholder":"I have hard news: Northgate is closing when our lease ends in March. Before anything else — every one of you is being offered a position at one of our other locations."},
    {"id":"hard-svc-senior-02","level":"senior","profession":"service","title":"The clean no on capex","scenario":"Your Riverside GM has asked twice for the $18k patio heater install, and your soft answers — 'let's revisit after Q3' — have kept the request alive. The truth is the capital's committed to the Lakeside build for two years. She deserves the no that lets her stop planning around a maybe.","task":"Write the 2-3 sentence response that says no clearly with the real reason.","tips":["A soft no that reads as later is a lie with better manners.","Give the actual reason — the capital is allocated — not a vague 'budget constraints'.","Tell her what would reopen it, if anything; a bounded no keeps trust."],"focus":["clarity","concision"],"placeholder":"The answer is no, and it won't change this year or next — the capital's committed to Lakeside. If we're over plan by Q4 next year, bring it back to me first."},
    {"id":"hard-svc-senior-03","level":"senior","profession":"service","title":"Behavior, impact, ask for the GM","scenario":"Your Downtown GM overrides your district policies in front of his staff — twice this month he's told servers 'ignore that memo, that's district nonsense'. He runs good numbers, which is why you've let it slide. The feedback needs to be surgical: the behavior, its cost, the ask.","task":"Write the 3-sentence feedback message: specific behavior, concrete impact, direct ask.","tips":["Name the behavior factually — the two dates, the exact words — no character commentary.","The impact is the system: staff at his site now ask which policies are real.","End with a doable ask: disagree with me in private, back the policy in public."],"focus":["clarity","structure"],"placeholder":"Twice this month you've told your team to ignore district policy in front of the floor — the result is your staff now treat every memo as optional. Challenge me on anything in private, but on the floor, I need you backing the policy."},
    {"id":"hard-svc-senior-04","level":"senior","profession":"service","title":"Telling the owner about the miss","scenario":"The year closes $60k under plan and the owner doesn't know yet — he's been watching the strong summer and assuming. Your draft opens with the summer highlights, building a cushion before the number. He'll feel the cushion for what it is: management of him.","task":"Write the 2-3 sentence message that leads with the miss, the size, and the driver.","tips":["The number first, unsoftened: $60k under, driven by the two-site roadwork.","No optimism sandwich — he can't plan around a miss he has to excavate.","Follow with what's already in motion, dated, so the news arrives with its response."],"focus":["clarity","impact"],"placeholder":"We're finishing the year $60k under plan — the roadwork sites never fully recovered their spring losses. Here's what's already in motion for Q1."},
    {"id":"hard-svc-senior-05","level":"senior","profession":"service","title":"The termination opener","scenario":"After two warnings and a final improvement plan, you're terminating the Kingsway manager — eight years with the company, well-liked, and consistently unable to run a compliant site. The meeting is at 2 p.m. Everything after the first sentence is logistics; the first sentence is the whole craft.","task":"Write the opening 2 sentences of the termination conversation.","tips":["The decision is made — state it as made, not as a discussion that might reopen.","No 'this is hard for me' — your feelings are not the topic and claiming them is theft.","Respect is brevity plus dignity: the fact, the effective date, then the supports."],"focus":["clarity","audience"],"placeholder":"Sam, I'm ending your employment with us, effective today. This follows the two warnings and the plan we set in March — I'll walk you through exactly what happens next and what support you leave with."},
    {"id":"hard-svc-senior-06","level":"senior","profession":"service","title":"Declining the franchisor's timeline","scenario":"The franchisor wants the Elm Street remodel done by June — peak season — which means closing your best site for its six best weeks. You've decided to refuse the timeline and accept the standards. Saying no to the brand requires the no to be unmistakable and the alternative to be ready.","task":"Write the 2-3 sentence response: the clear no, the reason, and your counter-date.","tips":["Decline the timeline specifically, not the remodel — precision keeps this a scheduling dispute, not defiance.","One reason at full strength: six peak weeks dark costs more than the remodel.","The counter-offer makes your no a plan: full remodel, September start, done by November."],"focus":["clarity","impact"],"placeholder":"I can't accept a June start — that closes our highest-volume site for its six best weeks. I'm committing to the full remodel with a September start, complete by mid-November."},
    {"id":"hard-svc-senior-07","level":"senior","profession":"service","title":"The no-raise conversation","scenario":"Your best front-desk lead asked for a $3-an-hour raise. She's earned it on merit and the budget genuinely can't carry it this year — the honest, miserable combination. A vague 'not right now' will read as 'they don't value me', and she'll be right to job-hunt on it.","task":"Write the 3-sentence answer: the no, the honest reason, and what is actually possible with dates.","tips":["Separate the two truths explicitly: the work merits it AND the budget can't fund it this year.","Never fake a process ('I'll fight for you upstairs') you don't intend to run.","Give the real path: the March review, the number you can defend, the shift-lead premium available now."],"focus":["clarity","audience"],"placeholder":"You've earned that raise on performance, and I can't pay it this year — those are both true, and you deserve to hear them together."},
    {"id":"hard-svc-senior-08","level":"senior","profession":"service","title":"Ending the ten-year vendor","scenario":"Your produce supplier of ten years — the one who carried you on credit through the pandemic — is losing the contract to the consolidated deal. He'll hear it from the market within a week if he doesn't hear it from you first. The letter has to be clean: the decision, the timeline, and the debt of gratitude paid honestly.","task":"Write the 3-4 sentence letter: decision first, terms, and the acknowledgment that's owed.","tips":["The decision in sentence one — a letter that opens with gratitude reads as a wind-up, and he'll know.","Terms that respect the history: 90 days' notice, not 30, and payment current on exit.","The gratitude must be specific to be worth anything: name the pandemic credit."],"focus":["clarity","audience"],"placeholder":"After ten years, we're moving our produce supply to a single consolidated vendor at the end of June — this letter is your 90 days' notice, and it comes with real gratitude."},
    {"id":"hard-svc-senior-09","level":"senior","profession":"service","title":"Resigning the unprofitable account","scenario":"The medical-office cleaning contract loses money on every visit — it was priced three wage increases ago, and the client has declined two re-pricing conversations. You're exiting the account. The letter must be unambiguous about the end date while leaving the relationship clean enough to return someday.","task":"Write the 3-sentence exit letter: the decision, the date, and the orderly transition.","tips":["State it as a decision, not an opening bid — 'we are ending' not 'we may need to consider'.","The transition is your professionalism on display: 60 days, full handover notes for the successor.","One sentence of honest reason without a lecture: the economics no longer work at this rate."],"focus":["clarity","structure"],"placeholder":"We'll be ending our cleaning services for your offices effective August 31. The current rate no longer covers our costs, and after two attempts to revisit it, the fair thing is a clean, well-managed exit."},
    {"id":"hard-svc-senior-10","level":"senior","profession":"service","title":"The step-down conversation","scenario":"You promoted Marcus to GM eight months ago and it hasn't worked — the site's numbers and his own health both say so. You want to keep him as assistant GM, where he was excellent. The conversation is a demotion no matter how you dress it, so don't dress it; deliver it with the respect of plainness.","task":"Write the opening 3 sentences: the decision, the honest why, and the real offer.","tips":["Say 'stepping back to assistant GM' once, plainly — euphemisms make him decode his own demotion.","The why is evidence he already knows: the numbers, the 70-hour weeks.","Make the offer real, not consolation: same site, a pay bridge for six months, and what excellent looked like when he had the right job."],"focus":["clarity","impact"]},
    {"id":"hard-svc-senior-11","level":"senior","profession":"service","title":"The underperforming site, told to investors","scenario":"Site four — the one you raised money for eighteen months ago — is running 30% under the pitch-deck projections. The quarterly letter is due, and your draft mentions site four in paragraph six. Investors forgive misses; they don't forgive discovering them by archaeology.","task":"Write the 2-3 sentences that put the miss up front with its size and your response.","tips":["Lead the letter with it — burying it costs more trust than the miss itself.","Numbers, not adjectives: 30% under projection, break-even pushed to month 30.","Your response with a date, and the checkpoint where you'll call it working or not."],"focus":["precision","clarity"],"placeholder":"Straight to the hard news: site four is running 30% below the projections in our raise materials, and break-even moves from month 18 to roughly month 30."},
    {"id":"hard-svc-senior-12","level":"senior","profession":"service","title":"The second failed audit","scenario":"Elm Street failed its re-audit — same two categories, ninety days after the first failure. The site manager is capable and drowning, and your message has to hold two truths: the consequences are now real (the franchisor's default clock starts), and there's a fourteen-day window to save it.","task":"Write the 3-sentence message: the result, the named consequence, and the intervention.","tips":["The consequence is the message: a third failure triggers the default process — say those words.","No blame narrative; the clock does the motivating.","The intervention is specific: you, on site, three days a week until the next audit."],"focus":["clarity","precision"],"placeholder":"Elm Street failed the re-audit — same two categories — and I need you to hear what that means: a third failure starts the franchise default process. Here's what the next fourteen days look like."},
    {"id":"hard-svc-senior-13","level":"senior","profession":"service","title":"Turning down the transfer","scenario":"Your best server at Mill Road applied for the Downtown opening — a shorter commute and better tips — and you're denying it, because Mill Road's fragile recovery collapses without her and two other seniors. That reason is real, but it's also using her excellence against her. She deserves the truth and a payment on it.","task":"Write the 3-sentence answer: the no, the honest reason, and what you're offering in return.","tips":["Tell the actual truth — 'Mill Road can't lose you right now' — she'll respect what she can verify.","Acknowledge the unfairness out loud; naming it is the only thing that defuses it.","Pay for what you're taking: first call on the next Downtown opening, in writing, plus the premium now."],"focus":["audience","clarity"],"placeholder":"I'm saying no to the transfer, and I owe you the real reason: Mill Road's recovery doesn't survive losing you this year. That's not fair to you, so here's what I'm doing about it."},
    {"id":"hard-svc-senior-14","level":"senior","profession":"service","title":"The bonus cut announcement","scenario":"The holiday bonus is halved this year — the roadwork sites bled the pool. Staff have been planning around the usual number since October, and the rumor mill already has fragments. Your all-staff note gets one job: the fact, the reason, and the restoration path, before the rumor version hardens.","task":"Write the 3-sentence announcement that front-loads the cut and its reason.","tips":["The number first: half, and what half is in dollars for a typical full-timer.","The reason is one honest sentence — the two-site year — not a paragraph of apology.","The path back matters most: what restores the full pool next year, stated as a commitment."],"focus":["clarity","impact"],"placeholder":"This year's holiday bonus will be half of last year's — the roadwork year at two sites drained the pool that funds it. Here's exactly what happened and what brings it back."},
    {"id":"hard-svc-senior-15","level":"senior","profession":"service","title":"No to the owner's menu idea","scenario":"The owner wants his late-night shawarma concept added at three sites — he's been talking about it for a month and has a name picked out. You've costed it: new equipment, split kitchen focus, and the numbers fail at every realistic volume. Saying no upward, to enthusiasm, is its own discipline.","task":"Write the 2-3 sentence response that declines with the numbers and keeps his trust.","tips":["Respect the idea by taking it seriously: you costed it fully, and lead with that.","The no rides on arithmetic, not taste — 'it needs 60 covers a night to break even; our best late-night comp does 25.'","Leave one door honestly open if one exists: the food-truck test that risks $8k, not $90k."],"focus":["impact","clarity"],"placeholder":"I costed the shawarma concept properly, because it deserved that — and it doesn't work: break-even needs 60 late-night covers and our best comparable does 25. There's a cheaper way to test whether I'm wrong."},
    {"id":"hard-svc-senior-16","level":"senior","profession":"service","title":"Reporting the theft","scenario":"The inventory investigation you've been running quietly for three weeks concluded this morning: the Bayview bar manager has been voiding sales and pocketing cash — roughly $9k over six months. The owner golfs with him. The message has to be facts first, airtight, and free of both drama and cushioning.","task":"Write the 3-sentence report: the finding, the evidence basis, and the action underway.","tips":["Findings, not suspicions: state what the evidence establishes and its dollar size.","Name the evidence type — void logs, camera cross-reference — so the finding arrives pre-verified.","Actions already taken (suspension, locks changed, lawyer briefed) tell him the situation is held."],"focus":["precision","clarity"],"placeholder":"The inventory investigation is conclusive: Bayview's bar manager has been voiding sales and taking cash — about $9,200 over six months, established by void logs matched to camera footage. He was suspended this morning; here's where things stand."},
    {"id":"hard-svc-senior-17","level":"senior","profession":"service","title":"The early-exit letter to the landlord","scenario":"You're exercising the break clause on the Northgate lease — eight years of tenancy, a good relationship, and a clause he probably forgot was in there. The letter is a legal notice that a human will read. It needs the formal elements exact and the tone clean of both apology and coldness.","task":"Write the 3-4 sentence notice: the exercise of the clause, the dates, the practical next steps.","tips":["The operative sentence carries the legal weight — clause number, notice date, termination date, exact.","No softening of the notice itself; ambiguity in a legal letter is expensive kindness.","The human paragraph follows the legal one: the walkthrough offer, the eight good years, named briefly."],"focus":["structure","precision"],"placeholder":"This letter serves as formal notice under clause 14.2 of our lease: we are exercising the break option, with tenancy ending September 30. We'd like to arrange the handover walkthrough for mid-September."},
    {"id":"hard-svc-senior-18","level":"senior","profession":"service","title":"The call to the injured guest's family","scenario":"Three days after the lobby fall, the guest's daughter calls, angry and scared, asking why nobody from management has reached out. The lawyer said keep contact minimal; your conscience and every hospitality instinct say otherwise. There is a version of this call that is both human and safe — it requires saying exactly what you mean.","task":"Write your opening 3 sentences on the call: care, facts of what you're doing, and no ducking.","tips":["Concern first and specific — her mother by name, the recovery, what the hospital needs.","You can care fully without conceding fault: 'I'm so sorry this happened to her' is human and safe.","Commit only to what you'll actually do: the direct line, the covered costs decision when it's made, the follow-up call Friday."],"focus":["audience","clarity"]},
    {"id":"hard-svc-senior-19","level":"senior","profession":"service","title":"Telling head office the opening slips","scenario":"Lakeside will not open March 3 — the electrical re-inspection pushed everything three weeks. Marketing has spent against the date, the VP announced it at the leadership offsite, and your name is on the plan. The message that ages well is the one with no spin in it.","task":"Write the 2-3 sentence message: the slip, the size, the new committed date.","tips":["New date in sentence one, and make it one you'd bet on — a second slip is the real career damage.","Own the miss without ceremony: the inspection sequencing was your call.","List what you've already re-booked (marketing, hiring starts) so the slip arrives half-absorbed."],"focus":["clarity","impact"],"placeholder":"Lakeside slips three weeks — new opening is March 24, and it's a date I'm confident in. The electrical re-inspection sequencing was my call, and here's what's already been moved."},
    {"id":"hard-svc-senior-20","level":"senior","profession":"service","title":"The back-office layoff","scenario":"Consolidating the district's admin work eliminates three office roles — real people who've processed payroll and invoices for years, one of them for a decade. They hear it today, individually, from you. The words 'restructuring' and 'streamlining' are banned; they already know what those words mean.","task":"Write the opening 2-3 sentences for those conversations.","tips":["Plain words: the role is being eliminated, the last day is the 30th — euphemisms insult the intelligence of people losing jobs.","It's the role, not the person — say that only if it's true, and here it is.","Severance, the reference, and job-search time on the clock: the supports go in the same breath as the news."],"focus":["audience","impact"]},
    {"id":"hard-svc-senior-21","level":"senior","profession":"service","title":"The finding against a favorite","scenario":"The harassment complaint against your most charismatic GM — the one whose site wins every award — was substantiated on three of four allegations by the outside investigator. You're informing him of the findings and the consequences. His charm is a weather system; the message has to be built to hold its shape inside it.","task":"Write the 3-sentence delivery: the findings, the consequence, and the boundary of the conversation.","tips":["State the findings as the investigator's conclusions, factually — this isn't your opinion to soften or debate.","The consequence is decided; deliver it decided: final warning, mandatory training, the transfer.","Set the boundary early: this conversation is about what happens next, not a relitigation of the investigation."],"focus":["clarity","precision"]},
    {"id":"hard-svc-senior-22","level":"senior","profession":"service","title":"The price-increase letter to contract clients","scenario":"Every commercial cleaning contract gets 7% at renewal — the wage floor and insurance did the arithmetic for you. Some clients will push back, a few may tender, and the letter that hides the number in paragraph three will make all of that worse. Write it the way you'd want to receive it.","task":"Write the 3-sentence letter: the increase up front, the honest driver, and what's not changing.","tips":["Number and date in sentence one; a hunt for the figure starts the relationship-damage early.","One driver, honestly: the wage floor is 80% of it, so say the wage floor.","End on what they keep: same crew, same supervisor, response guarantee intact — the things a cheaper bidder can't promise."],"focus":["audience","impact"],"placeholder":"At renewal on July 1, your contract price increases 7% — the new wage floor accounts for most of it, and we won't cut crew hours to dodge it. Here's what stays exactly the same."},
    {"id":"hard-svc-senior-23","level":"senior","profession":"service","title":"The buyout conversation","scenario":"Fifteen years in, you and your business partner want different companies: he wants dividends and no debt; you want to build to twelve sites. The partnership isn't broken, which is what makes this hard — you're proposing to buy him out before it breaks. The opening has to be honest enough that he doesn't spend the conversation hunting for the hidden agenda.","task":"Write the opening 3 sentences: what you're proposing, why now, and the fair-process commitment.","tips":["Say the actual thing: 'I want to buy your share' — approach-hints poison the well with suspicion.","The why is the divergence, stated without blame: two right answers, one company.","The process commitment makes it discussable: independent valuation, his advisors, no deadline pressure."],"focus":["impact","clarity"],"placeholder":"I want to buy your half of the company, and I want to tell you exactly why: you want the business to pay us, I want it to grow, and both of us are right — in different companies."},
    {"id":"hard-svc-senior-24","level":"senior","profession":"service","title":"The internal candidate who didn't get it","scenario":"Priya applied for the Downtown GM role and told her whole team she was applying. You chose the external candidate — more openings experience, which Downtown's relaunch needs. Priya finds out at 3 p.m. tomorrow when the announcement goes out, unless you tell her at 9 a.m. yourself, with the real reason.","task":"Write the opening 3 sentences of the 9 a.m. conversation.","tips":["Before the announcement, from you, with the actual reason — all three or it's not respect.","The real reason, specifically: the relaunch needs someone who's done three openings; she's done none — yet.","The path forward has to be concrete: the assistant role on the relaunch, and the openings experience it builds."],"focus":["audience","clarity"],"placeholder":"Priya, before tomorrow's announcement, you're hearing this from me: I chose an outside candidate for Downtown, and I want you to know the real reason."},
    {"id":"hard-svc-senior-25","level":"senior","profession":"service","title":"The final warning","scenario":"The Fairview supervisor has missed the same compliance standard through a verbal warning and a written one. Today's conversation is the final warning, and the kindest version is the clearest: the specific gap, the specific standard, the specific consequence, the specific date. Vagueness here would be setting him up.","task":"Write the final warning's core 3 sentences: the gap, the required standard with dates, and the stated consequence.","tips":["Cite the record: the two prior warnings, dated — this conversation has a paper spine.","The standard must be checkable: logs complete and verified daily, reviewed each Friday for 60 days.","Say the consequence in plain words: the next failure ends his employment. He should leave with zero ambiguity."],"focus":["precision","structure"],"placeholder":"This is a final warning, and I want to be completely clear about what it means. The temperature logs have failed the standard twice since your written warning in April; for the next 60 days they must be complete and verified daily, reviewed with me every Friday."}
  ],
  "putting-it-together": [
    {"id":"together-svc-senior-01","level":"senior","profession":"service","title":"The complete turnaround memo","scenario":"The owner has given you thirty minutes of his attention for the Westgate decision: fund the turnaround or wind the site down. Everything you've practiced converges here — the verdict up front, one governing idea, three workstreams, precise numbers, an owned recommendation, and the ask with a date.","task":"Write the full memo in 6-8 sentences integrating all of it.","tips":["Sentence one: your recommendation and the headline number.","One governing idea (management, not market), three dated workstreams beneath it.","End on the bounded ask: the dollars, the checkpoints, and the kill criteria you'll hold yourself to."],"focus":["structure","impact"],"placeholder":"Recommendation: fund the Westgate turnaround — $45k over two quarters — because the problem is fixable management, not a broken market."},
    {"id":"together-svc-senior-02","level":"senior","profession":"service","title":"One closure, three channels","scenario":"The Northgate closure goes out through three doors tomorrow: a memo to head office, your spoken words to the site's staff, and a notice for the guests who've eaten there for twenty years. Same fact, three audiences, three registers — and any mismatch between versions will be screenshotted.","task":"Write the one core sentence for each channel, showing how the same fact shifts.","tips":["Head office: the decision and the numbers behind it.","Staff: the fact plus their future in the same breath.","Guests: gratitude and where to find you — no corporate anatomy.","The facts must be identical across all three; only the frame moves."],"focus":["audience","clarity"]},
    {"id":"together-svc-senior-03","level":"senior","profession":"service","title":"The flood update, done right","scenario":"A burst pipe has closed half the hotel's ground floor on a sold-out weekend. Ninety minutes in, you owe the owner the update: what happened, guest impact, cost exposure, next steps — BLUF, structured, precise, and steady, written while your phone buzzes every forty seconds.","task":"Write the full 5-6 sentence update integrating lead, structure, precision, and presence.","tips":["First line: situation and control status — 'contained, no guest injuries, 14 rooms out'.","Fixed shape: impact, cause, actions, next update time.","Numbers not adjectives; a named hour for the next update is what calm sounds like."],"focus":["structure","impact"],"placeholder":"Ground-floor flood is contained — no injuries, 14 rooms out of service on a sold-out night. Here's where we stand:"},
    {"id":"together-svc-senior-04","level":"senior","profession":"service","title":"Edit your manager's memo","scenario":"Your Riverside GM drafted the equipment-funding request that goes to head office under your name. The case is right and the writing buries it: the ask in paragraph four, hedges everywhere, kitchen jargon head office won't parse. You have one editing pass before the noon deadline.","task":"Rewrite the opening paragraph as your edited version, 3-4 sentences.","tips":["Move the ask and the payback to sentence one.","Cut every hedge that isn't a real risk; translate 'low-boy' and 'the pass' into equipment and dollars.","Keep her strongest evidence — the two service-week outages — and cut the rest."],"focus":["concision","audience"],"placeholder":"Requesting $22k to replace Riverside's failing refrigeration line — it's caused two service outages this quarter, and the replacement pays back in 14 months."},
    {"id":"together-svc-senior-05","level":"senior","profession":"service","title":"'We're full' to the events team","scenario":"The events coordinator keeps selling December bookings your kitchen can't serve — she's paid on volume and doesn't see the kitchen's ceiling. You need to cap December at 40 events: her frame first, the constraint stated hard, and her 'so we just turn away money?' pushback answered before she says it.","task":"Write the full 5-6 sentence message integrating audience, hard message, and pre-emption.","tips":["Open in her currency: protecting her clients' events and her repeat-booking rate.","The cap is a hard number with a reason: 40 events is where quality holds.","Pre-empt the revenue objection: one botched gala costs more bookings than three declined ones."],"focus":["audience","impact"]},
    {"id":"together-svc-senior-06","level":"senior","profession":"service","title":"The complete renewal counter","scenario":"The landlord's renewal offer sits at plus-15% and your reply is the whole negotiation in one email: lead with your position, evidence from the market comps you pulled, the vacant-street stakes, and a specific counter with a deadline. Every module you've done is a paragraph of this email.","task":"Write the full 5-6 sentence counter-offer email.","tips":["Position first: renewing at plus-5% with a five-year term — anchor before arguing.","Two evidence points: the comps and your covenant record; then the vacancy stakes in one line.","Close with the deadline that makes it real: your alternative space option expires June 1."],"focus":["structure","precision"],"placeholder":"We want to renew, and here's our position: plus-5% on a five-year term, against your plus-15."},
    {"id":"together-svc-senior-07","level":"senior","profession":"service","title":"The annual letter, integrated","scenario":"The year's investor letter has to do everything at once: a verdict sentence that survives the golf course, a spine of three claims, precise numbers under each, honest treatment of the site-four miss, and calibrated confidence about next year. Six pages last year; one page this year.","task":"Write the letter's opening 5-6 sentences: verdict, the three-claim spine, and the honest miss.","tips":["The verdict sentence first — judgment plus number.","Three claims that together tell the year; the miss gets claim status, not a footnote.","Close the opening with next year's bet and your confidence level, stated like you mean it."],"focus":["structure","impact"],"placeholder":"This was a strong year with one real disappointment: the group grew 7%, five of six sites beat plan, and site four missed badly — here's all three stories."},
    {"id":"together-svc-senior-08","level":"senior","profession":"service","title":"Acquisition-day script","scenario":"At 8 a.m. you stand in front of the two acquired sites' combined staff — forty strangers who've feared this day for a month. The five minutes needs everything: hard clarity about what changes, honest boundaries on what's undecided, one believable story about where this goes, and a first promise small enough to keep by Friday.","task":"Write the first 5-6 sentences of the script.","tips":["Lead with the thing they most fear, answered: nobody's site is closing, nobody's shift changes this month.","One honest boundary: pay integration is being worked out, answer by the 30th.","End the opening on the small keepable promise — you, on site, every Tuesday, asking what's broken."],"focus":["audience","impact"]},
    {"id":"together-svc-senior-09","level":"senior","profession":"service","title":"The bank package cover memo","scenario":"The line-increase application is forty pages of financials; the cover memo is the only page the credit committee reads aloud. One page to do it all: the ask up front, the three numbers that carry it, the concentration risk named before they find it, and a close that sounds like a company worth backing.","task":"Write the full 5-6 sentence cover memo.","tips":["Ask, amount, and purpose in the first sentence.","Three numbers with their trend: coverage, growth, concentration — including the one that isn't flattering.","Name your risk before their analyst does; it converts a red flag into evidence of competence."],"focus":["precision","structure"],"placeholder":"We're requesting an increase in our operating line from $50k to $100k to fund winter contract mobilization — payroll runs weekly, the contracts pay in 60 days."},
    {"id":"together-svc-senior-10","level":"senior","profession":"service","title":"The statement and the staff note","scenario":"The billing-dispute video has been picked up by a local news site, and two messages leave your desk within the hour: the public statement and the internal note to all staff. Same facts, opposite failure modes — the statement can't be defensive, the staff note can't be corporate. Each will leak into the other's audience.","task":"Write both: the 2-sentence public statement and the 2-sentence staff note.","tips":["Statement: what happened, what you did — quotable, calm, complete.","Staff note: what to say if asked, and who handles press — protection, not spin.","Write each assuming the other audience reads it, because they will."],"focus":["audience","clarity"]},
    {"id":"together-svc-senior-11","level":"senior","profession":"service","title":"The full incident report","scenario":"The contractor-ladder incident needs its formal report to head office, and it's a test of everything: four labeled sections, conclusions first in each, facts separated from judgment, precise scope, an owned assessment, and not one sentence of padding. This document gets read again if there's ever a lawsuit.","task":"Write the complete report in 6-8 sentences across the four sections: what happened, impact, cause, fix.","tips":["Each section leads with its conclusion; details follow.","Facts carry times and names; your judgment is labeled as judgment.","Write for the second reader — the one holding it in a deposition two years from now."],"focus":["structure","precision"]},
    {"id":"together-svc-senior-12","level":"senior","profession":"service","title":"The ninety-second district update","scenario":"The VP's assistant just called: you have the first slot on tomorrow's regional call, ninety seconds, all districts listening. Headline, the one risk, the one ask — spoken, signposted, no dashboard tour. The managers who ramble get remembered for rambling.","task":"Write the spoken 5-6 sentence update, timed for ninety seconds.","tips":["Signpost in the first breath: 'headline, one risk, one ask.'","The district number first, then the risk stated with its size and your response.","End on the ask, or a clean 'nothing needed' — both are strong; trailing off is not."],"focus":["concision","impact"],"placeholder":"Ninety seconds, three things: the headline, one risk, one ask. District's up 5% with five of six sites on plan."},
    {"id":"together-svc-senior-13","level":"senior","profession":"service","title":"The pre-send checklist, run","scenario":"Your district budget email to head office is drafted and the deadline is in an hour. Run the full checklist against it: does sentence one carry the ask, is there one governing idea, can a third of the words go, are the claims specific, did you take a position? Fix what fails.","task":"Write the final version of the email's opening paragraph (3-4 sentences) after the checklist pass.","tips":["The five checks, in order: lead, structure, cut, precision, position.","Most drafts fail check three worst — cut before you polish.","The paragraph that survives all five checks is shorter, sharper, and sounds more like a decision."],"focus":["concision","structure"],"placeholder":"Requesting approval of the FY district budget: $1.24M, up 4%, driven entirely by the wage floor — everything else is held flat."},
    {"id":"together-svc-senior-14","level":"senior","profession":"service","title":"The pilot proposal, complete","scenario":"The delivery pilot proposal to the franchisor is due, and it's the full stack in one page: SCQA to build the logic, postal-code evidence for precision, the brand-risk objection pre-empted, a bounded design with a kill switch, and a stated position you own. This is the document their brand committee reads without you in the room.","task":"Write the proposal's core 6 sentences: S, C, Q, A, the evidence, and the pre-empted objection.","tips":["Situation and complication set the trap; the question should ask itself.","Your answer is the bounded pilot — two sites, ninety days, weekly audits, kill criteria.","Give the objection a full sentence and its answer another; committees trust proposals that argued with themselves."],"focus":["structure","impact"]},
    {"id":"together-svc-senior-15","level":"senior","profession":"service","title":"The new GM's first letter","scenario":"Dana starts as Downtown GM on Monday, and your welcome letter is the template her whole tenure gets built on. It needs clear expectations with numbers, the honest state of the site including the two problems you're handing her, what she owns versus what needs your sign-off, and a register that says trusted colleague, not subordinate.","task":"Write the letter's core 5-6 sentences.","tips":["Expectations as numbers with dates: the labor target, the audit score, the ninety-day review.","Hand over the problems honestly — discovering them herself in week three costs trust both ways.","Draw the authority line explicitly: what she decides alone, what comes to you. Ambiguity there breeds either timidity or surprises."],"focus":["audience","clarity"],"placeholder":"Dana — Downtown is yours as of Monday, and I want you starting with the full picture: the two numbers I care about, the two problems I'm handing you, and exactly what's yours to decide."},
    {"id":"together-svc-senior-16","level":"senior","profession":"service","title":"The apology that keeps the account","scenario":"Your crew set off the alarm system at your biggest office client's headquarters at 2 a.m. — police attended, the facilities director was woken, and their CEO asked questions. The apology letter is the account's last chance and everything has to work: front-loaded ownership, precise cause, the systemic fix, a real remedy, and no groveling.","task":"Write the full 5-6 sentence letter.","tips":["Own it in sentence one with specifics — 'our crew, our error, your 2 a.m.'.","The cause and fix must be systemic: not 'we reminded the team' but the new arming protocol with verification.","One remedy with a number, one apology, zero repetitions of either."],"focus":["audience","impact"],"placeholder":"Our crew caused Tuesday's 2 a.m. alarm at your headquarters — the arming sequence was done in the wrong order, and that error is fully ours."},
    {"id":"together-svc-senior-17","level":"senior","profession":"service","title":"The mixed review, integrated","scenario":"The Bayview GM's annual review is the whole toolkit in one conversation: a verdict that holds both truths, three themes from forty observations, the hard message about her hiring blind spot delivered clean, precise evidence under every claim, and a next-year bar with numbers. She's talented, proud, and will remember this hour all year.","task":"Write the review's opening 5 sentences: verdict, the three themes, and the hard message stated plainly.","tips":["The verdict sentence carries both truths at honest weight — don't let the praise soften the gap into fog.","Announce the three themes so she can follow; the hard one isn't hidden in the middle.","Behavior-impact-ask for the blind spot: the three hires, the pattern, the change you need."],"focus":["clarity","structure"]},
    {"id":"together-svc-senior-18","level":"senior","profession":"service","title":"The price-increase town hall","scenario":"You're announcing the menu increase to all staff before it hits the tables — because they face the guests. The five minutes integrates everything: news first, the honest why with numbers, what it means for them and their tips, the guest-facing sentence you're giving them, and their hardest question pre-answered.","task":"Write the spoken 5-6 sentence announcement.","tips":["The change and date first; two hundred people came to hear the thing, not the wind-up.","Give them the exact sentence to say at the table — that's the gift of the meeting.","Pre-empt their real question — 'will guests tip less?' — with what happened at the last increase: check averages rose, tip percentages held."],"focus":["audience","impact"]},
    {"id":"together-svc-senior-19","level":"senior","profession":"service","title":"The site-five one-pager","scenario":"Your investors asked for one page on site five before Thursday's dinner. One page for the whole argument: the governing idea, the deal's numbers with their build, the before/after, the risk you're most worried about named by you first, and the specific ask with its deadline. White space is part of the message.","task":"Write the one-pager's 6 sentences.","tips":["Governing idea first: this corner plus this proven model equals the group's best unit economics yet.","Numbers with builds — the $380k, the month-14 break-even, the site-three comp curve.","Name your top risk yourself, with its mitigation; an investor who finds it first stops trusting the page."],"focus":["precision","impact"],"placeholder":"Site five is the group's best expansion economics to date: a corner location with 40% more foot traffic than site three, at 10% more rent, on a model we've now proven twice."},
    {"id":"together-svc-senior-20","level":"senior","profession":"service","title":"The vendor-switch memo, complete","scenario":"The linen-supplier switch memo to head office is a small document that needs the whole craft: recommendation and savings up front, the 60-day trial evidence, the transition plan with dates, the service-risk objection pre-empted, and an ask with a deadline tied to the incumbent's renewal date. One page, no fat.","task":"Write the full 5-6 sentence memo.","tips":["Recommendation, vendor, and the $2,100 monthly saving in sentence one.","The trial data is the spine: fill rates, quality scores, the missed-delivery count — theirs and the incumbent's.","Pre-empt the switching-risk question with the transition overlap plan, and close on the renewal-date deadline that makes 'decide later' expensive."],"focus":["structure","precision"],"placeholder":"Recommendation: switch linen supply to Meridian across all four properties, saving $2,100 a month — verified by a 60-day head-to-head trial at Harbourview."},
    {"id":"together-svc-senior-21","level":"senior","profession":"service","title":"'Explain your quarter'","scenario":"Head office's email is four words: 'Explain your Q3, please.' The reply is the full stack under pressure — a governing idea instead of six site stories, drivers quantified, your own mistakes owned at their true size, the fix with dates, and a forecast you'd stake your credibility on. Two of the six sites missed badly.","task":"Write the reply's 5-6 sentences.","tips":["One governing sentence that explains the quarter — then the evidence under it.","Quantify the drivers and split them honestly: external, structural, and yours.","End on the forecast with your confidence stated — a reply that only explains the past answers half the email."],"focus":["structure","precision"],"placeholder":"Q3 in one sentence: the district's core five sites grew 4%, and Westgate's management gap erased nearly all of it."},
    {"id":"together-svc-senior-22","level":"senior","profession":"service","title":"The renew-or-relocate email, whole","scenario":"June 1 is three weeks out and the owner needs the flagship lease decision teed up completely in one email: the decision and deadline first, both options in one disciplined line each, your recommendation owned with its deciding reason, the number that would change your mind, and the process from his 'yes' to a signed lease.","task":"Write the complete 5-6 sentence email.","tips":["Decision and deadline in sentence one; options in one line each — cost, disruption, risk.","Your recommendation with the single deciding reason, not the full analysis.","'What would change my mind' is the sentence that proves the recommendation was reasoned, not reflexive."],"focus":["structure","clarity"],"placeholder":"The flagship lease decision is due June 1, and this email has everything you need to make it."},
    {"id":"together-svc-senior-23","level":"senior","profession":"service","title":"The audit failure with a plan","scenario":"Elm Street's re-audit result goes to the franchisor today, from you, before their system flags it. The message integrates hard news and turnaround: the failure stated first without cushioning, cause owned precisely, the fourteen-day corrective plan with named actions and dates, and your personal involvement as the guarantee. Getting ahead of it is the whole play.","task":"Write the full 5-6 sentence message.","tips":["The result in sentence one — beating their system to the news is worth more than any framing.","Cause owned at its exact size: supervision, during the handover, on your watch.","The plan carries dates and your name: on-site three days a week, re-audit requested for the 28th. Asking for the re-audit is confidence they can measure."],"focus":["clarity","structure"],"placeholder":"Elm Street failed its re-audit yesterday — same two categories — and I want you hearing it from me with the plan already running."},
    {"id":"together-svc-senior-24","level":"senior","profession":"service","title":"The Friday five-liner","scenario":"You've committed to a weekly five-line update for the owner: headline, then four bullets — numbers, problem, fix, decision-needed. This week fights the format: a record Tuesday, the freezer saga's final invoice, a server injury WSIB claim, the Lakeside slip, and a manager resignation. The discipline is the drill.","task":"Write this week's five-liner: one headline sentence plus the four one-line bullets.","tips":["The headline takes the week's most consequential item — probably not the record Tuesday.","One line each, hard limit; anything needing more gets flagged for a call, not expanded.","The decision-needed bullet always closes, so his reply-brain is already engaged."],"focus":["concision","clarity"],"placeholder":"Mixed week: record Tuesday sales, but Lakeside slips three weeks and we lost a manager."},
    {"id":"together-svc-senior-25","level":"senior","profession":"service","title":"Rewrite your worst email","scenario":"Scroll your sent folder for the worst email you actually sent this month — the buried ask, the hedge parade, the 400-word 'quick question'. Every drill in this course was training for this: rewrite the real thing with the full checklist — lead, structure, cut, precision, position — and notice exactly which habits your fingers defend.","task":"Write the rewritten version of your real email, and one sentence naming the habit it exposed.","tips":["Use a real email — invented examples let you dodge your actual patterns.","Run the checks in order: fix the lead first, structure second, cut third.","The named habit is the takeaway: the specific reflex to catch before your next send."],"focus":["concision","impact"]}
  ],
};
